INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-11-27', E'이스라엘의 족보들 (역대상 9장)', E'역대상 9장', E'역대상의 족보는 단순한 이름의 나열이 아니라 하나님의 구원 역사가 어떻게 이어져 왔는지를 보여주는 귀중한 기록입니다. 9장은 바벨론 포로에서 돌아온 이스라엘 백성들이 예루살렘과 각 성읍에 정착하는 모습을 그려내고 있습니다. "유다가 범죄함으로 말미암아 바벨론으로 사로잡혀 갔더니"(대상 9:1)라는 구절은 포로 생활의 원인을 분명히 지적하면서도, 그럼에도 불구하고 하나님께서 언약 백성을 포기하지 않으셨음을 암시합니다.\n\n포로에서 돌아온 첫 거주자들의 명단은 의미심장합니다. 제사장들과 레위인들, 그리고 성전 봉사자인 느디님 사람들이 가장 먼저 언급되는데, 이는 회복된 공동체의 중심이 무엇인지를 보여줍니다. 성전 예배의 회복이야말로 이스라엘 공동체 재건의 핵심이었던 것입니다. 특별히 성전 문지기들의 직무가 상세히 기록된 것은 그들의 역할이 단순한 경비가 아니라 거룩한 공간을 지키는 영적 사명이었음을 알려줍니다. 그들은 대대로 이 직분을 물려받으며 충성스럽게 섬겼고, 다윗과 사무엘 때부터 세워진 이 제도는 포로 귀환 후에도 그대로 이어졌습니다.\n\n역대기 기자는 특별히 레위인들의 다양한 직무를 세밀하게 기록합니다. 성전 기구를 관리하는 자, 제물과 향품을 담당하는 자, 전병을 굽는 자, 진설병을 준비하는 자, 그리고 찬송으로 섬기는 자들까지, 각자가 맡은 역할이 있었습니다. "주야로 자기 직분에 전념하므로 다른 일은 하지 아니하였더라"는 표현은 그들의 헌신적인 섬김을 잘 보여줍니다. 이처럼 하나님의 집을 섬기는 일에는 크고 작음이 없으며, 각자의 자리에서 충성된 청지기로 살아가는 것이 중요함을 깨닫게 됩니다.\n\n장의 마지막 부분은 사울 왕가의 계보로 마무리되는데, 이는 곧 이어질 다윗 왕조 이야기를 위한 준비입니다. 하나님께서는 실패한 왕조를 통해서도 당신의 구원 계획을 이루어 가셨고, 포로에서 돌아온 백성들에게 새로운 소망을 주셨습니다. 오늘 우리도 각자의 자리에서 하나님 나라를 위해 충성스럽게 섬기는 일꾼이 되어야 하겠습니다.', E'오늘의 핵심\n포로에서 귀환한 이스라엘 백성들이 가장 먼저 한 일은 성전 예배를 회복하는 것이었으며, 각자 맡은 직분에 충성된 레위인들의 섬김이 그 중심에 있었습니다.\n\n묵상 질문\n1. 포로 귀환 후 제사장과 레위인들이 가장 먼저 정착한 것은 무슨 의미일까요?\n2. 성전을 섬기는 다양한 직무들처럼 내가 하나님 나라를 위해 감당할 역할은 무엇일까요?\n3. 실패와 회복의 역사 속에서도 신실하게 일하시는 하나님을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-11-28', E'왕이 된 다윗과 그의 용사들 (역대상 10장)', E'역대상 10장', E'길보아 산에서 벌어진 전투는 이스라엘 역사의 비극적인 전환점이 되었습니다. 블레셋과의 전투에서 이스라엘 군대는 참패를 당했고, 사울 왕과 그의 세 아들이 함께 전사하는 비극적인 결말을 맞이했습니다. 역대기 기자는 사울 왕조의 몰락을 단순한 군사적 패배로 기록하지 않고, 그 영적인 원인을 분명히 밝혀줍니다.\n\n사울의 최후는 한 왕조의 종말을 넘어서 불순종의 결과가 무엇인지를 보여주는 엄중한 경고였습니다. 역대기는 "사울이 죽은 것은 여호와께 범죄하였기 때문이라"(13절)고 명확하게 진단합니다. 그가 여호와의 말씀을 지키지 않았고, 신접한 자를 찾아가 도움을 구했으며, 정작 여호와께는 묻지 않았다는 것입니다. 엔돌의 신접한 여인을 찾아간 사건은 사울이 얼마나 하나님으로부터 멀어졌는지를 보여주는 결정적인 증거였습니다.\n\n그러나 암흑 같은 비극 속에서도 희망의 빛이 비추고 있었습니다. 길르앗야베스 사람들이 목숨을 걸고 사울과 그 아들들의 시체를 수습하여 장사 지낸 일은 과거 사울이 그들에게 베푼 은혜를 잊지 않은 신의 있는 행동이었습니다. 이들의 헌신적인 행동은 비록 사울이 실패한 왕이었지만, 그에게도 아름다운 순간들이 있었음을 상기시켜 줍니다.\n\n사울 왕조의 몰락은 끝이 아닌 새로운 시작을 위한 하나님의 섭리였습니다. 역대기는 "여호와께서 그를 죽이시고 그 나라를 이새의 아들 다윗에게 넘겨 주셨더라"(14절)고 기록함으로써, 역사의 주관자이신 하나님께서 이미 다음 왕을 준비하고 계셨음을 보여줍니다. 사울의 실패는 다윗이라는 새로운 지도자를 통해 하나님의 백성을 바로 세우시려는 하나님의 더 큰 계획 속에 있었던 것입니다.', E'오늘의 핵심\n사울의 비극적 최후는 하나님의 말씀에 불순종하고 하나님 대신 다른 것에 의지한 결과였으며, 하나님께서는 이미 다윗을 통한 새로운 시대를 준비하고 계셨습니다.\n\n묵상 질문\n1. 사울이 하나님께 묻지 않고 신접한 자를 찾아간 것처럼, 내가 하나님보다 먼저 의지하는 것은 무엇인가요?\n2. 길르앗야베스 사람들의 신의 있는 행동을 통해 배울 수 있는 은혜를 갚는 삶의 자세는 무엇일까요?\n3. 내 삶의 실패와 좌절 속에서도 새로운 시작을 준비하시는 하나님의 손길을 느끼고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-11-29', E'왕이 된 다윗과 그의 용사들 (역대상 11장)', E'역대상 11장', E'헤브론에 모인 온 이스라엘이 다윗을 왕으로 세우는 장면은 하나님의 약속이 성취되는 역사적 순간입니다. "네가 내 백성 이스라엘의 목자가 되며 내 백성 이스라엘의 주권자가 되리라"(대상 11:2)는 하나님의 말씀이 마침내 실현된 것입니다. 사울의 비극적 죽음 이후 분열될 수 있었던 이스라엘이 다윗 앞에서 하나로 결속되는 모습은 하나님께서 준비하신 지도자의 영향력을 보여줍니다.\n\n다윗의 첫 번째 과업은 여부스 원주민이 차지하고 있던 예루살렘을 정복하는 일이었습니다. 난공불락으로 여겨졌던 이 성을 점령하고 다윗 성으로 명명한 것은 단순한 군사적 승리 이상의 의미를 담고 있습니다. 예루살렘은 훗날 하나님의 성전이 세워질 거룩한 도성이 되며, 이스라엘 신앙의 중심지가 됩니다. 만군의 여호와께서 함께하시니 다윗이 점점 강성하여 갔다는 기록은 그의 성공이 개인의 능력이 아닌 하나님의 은혜였음을 분명히 합니다.\n\n본문의 대부분을 차지하는 용사들의 명단은 다윗 왕국의 든든한 기초를 보여줍니다. 특별히 세 용사가 베들레헴 우물물을 길어온 일화는 깊은 감동을 줍니다. 생명의 위험을 무릅쓰고 가져온 물을 다윗이 차마 마시지 못하고 여호와께 부어드린 행동은 부하들의 헌신을 귀하게 여기는 지도자의 마음을 보여줍니다. 이러한 상호 신뢰와 존중의 관계가 다윗 왕국을 견고하게 만든 영적 토대였습니다.\n\n다양한 지파와 배경에서 모인 용사들의 이름이 하나하나 기록된 것은 하나님 나라의 일에 참여한 모든 이들의 헌신이 기억되고 있음을 알려줍니다. 베냐민 지파에서도, 심지어 이방인 출신에서도 다윗의 용사가 된 이들이 있었다는 사실은 하나님의 나라가 혈통이나 신분이 아닌 믿음과 헌신으로 세워짐을 증거합니다.', E'오늘의 핵심\n하나님께서는 약속하신 대로 다윗을 왕으로 세우시고, 신실한 동역자들을 통해 그의 왕국을 견고하게 세워가십니다.\n\n묵상 질문\n1. 다윗이 베들레헴 우물물을 마시지 않고 하나님께 부어드린 마음을 묵상해 보셨나요?\n2. 나는 하나님의 일에 이름 없이 헌신하는 용사의 삶을 살고 있나요?\n3. 공동체의 지도자와 구성원 간의 신뢰 관계를 위해 내가 실천할 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-11-30', E'왕이 된 다윗과 그의 용사들 (역대상 12장)', E'역대상 12장', E'다윗이 사울에게 쫓겨 시글락에 숨어 있을 때, 놀라운 일이 일어나고 있었습니다. 이스라엘 각 지파에서 용사들이 속속 다윗에게로 모여들기 시작한 것입니다. 역대기 기자는 이들의 명단을 상세히 기록하며, 하나님께서 어떻게 다윗을 이스라엘의 왕으로 세우셨는지를 보여줍니다.\n\n가장 먼저 놀라운 것은 사울의 동족인 베냐민 지파에서도 다윗을 따르는 용사들이 나타났다는 사실입니다. 이들은 활을 다루는 데 능숙했고, 좌우 손을 자유자재로 사용하는 뛰어난 전사들이었습니다. 자기 지파의 왕을 버리고 쫓기는 다윗을 선택한 그들의 결단은 하나님의 뜻을 분별하는 영적 통찰력에서 나온 것이었습니다.\n\n갓 지파의 용사들은 "그의 얼굴은 사자 같고 빠르기는 산의 사슴 같으니"(대상 12:8)라고 묘사될 정도로 강인했습니다. 정월에 요단 강물이 범람할 때도 거침없이 건너 다윗에게 합류한 그들의 모습은 하나님의 부르심에 대한 절대적 헌신을 보여줍니다.\n\n특히 감동적인 것은 성령이 아마새를 감싸시며 다윗을 향한 충성을 고백하게 하신 장면입니다. 그는 "당신의 하나님이 당신을 도우심이니이다"라고 선언하며, 다윗의 왕권이 하나님께로부터 온 것임을 확증했습니다. 이는 단순한 정치적 선택이 아니라 하나님의 주권적 역사에 대한 신앙고백이었습니다.\n\n헤브론에 모인 이스라엘 전 지파의 군대는 "하나님의 군대"와 같았다고 기록됩니다. 유다에서 6,800명, 시므온에서 7,100명, 레위에서 4,600명 등 각 지파에서 온 십여만 명이 넘는 용사들이 "다 성심으로" 다윗을 왕으로 세우고자 했습니다. 이들이 사흘 동안 함께 먹고 마시며 기뻐한 것은 하나님의 뜻이 성취되는 것을 축하하는 거룩한 잔치였습니다.\n\n다윗이 왕이 될 수 있었던 것은 그의 개인적 능력 때문만이 아니었습니다. 하나님께서 각 지파에서 준비된 사람들을 보내시고, 성령으로 그들의 마음을 움직이셔서 다윗을 중심으로 하나 되게 하신 것입니다. 이렇게 하나님의 나라는 한 사람의 영웅이 아니라, 하나님의 뜻에 순종하는 신앙 공동체를 통해 세워집니다.', E'오늘의 핵심\n하나님께서는 각 지파에서 준비된 사람들을 다윗에게 보내시고, 성령으로 그들의 마음을 하나 되게 하셔서 다윗 왕국의 기초를 놓으셨습니다.\n\n묵상 질문\n1. 하나님의 뜻을 분별하고 따르기 위해 때로는 익숙한 것을 버려야 할 때가 있나요?\n2. 내가 속한 신앙 공동체가 하나님의 뜻으로 하나 되기 위해 무엇이 필요할까요?\n3. 하나님께서 나를 통해 이루시려는 일에 동역자를 보내주실 것을 기도하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-01', E'언약궤의 예루살렘 안치 (역대상 13장)', E'역대상 13장', E'다윗이 이스라엘 전체의 왕이 된 후 가장 먼저 추진한 일은 하나님의 언약궤를 예루살렘으로 모셔오는 것이었습니다. 언약궤는 하나님의 임재를 상징하는 거룩한 기물로서, 이미 450여 년 전 광야에서 하나님께서 모세에게 만들도록 명하신 것입니다. 그런데 이 언약궤는 엘리 제사장 시절 블레셋에게 빼앗겼다가 돌아온 후, 기럇여아림에 있는 아비나답의 집에서 약 70년 동안 방치되어 있었습니다. 사울왕 시대에는 아무도 언약궤에 관심을 기울이지 않았던 것입니다.\n\n다윗은 천부장과 백부장을 비롯한 모든 지휘관들과 의논하고, 온 백성의 뜻을 물어 언약궤를 옮기기로 결정합니다. 그는 애굽의 시홀 시내에서부터 하맛 어귀까지 온 이스라엘을 불러모아 이 거룩한 일에 동참하게 합니다. 온 백성이 하나님 앞에서 힘을 다하여 뛰놀며 노래하고, 수금과 비파와 소고와 제금과 나팔로 연주하는 축제의 분위기였습니다.\n\n그러나 기돈의 타작마당에 이르렀을 때 비극이 일어납니다. 소들이 뛰자 언약궤가 기울어지려 하고, 웃사가 손을 펴서 궤를 붙들었습니다. 그 순간 하나님의 진노가 임하여 웃사가 즉사하고 맙니다. 이 사건은 우리에게 중요한 교훈을 전해줍니다. 하나님께서는 민수기 4장에서 언약궤는 오직 레위 자손 중 고핫 자손이 어깨에 메어 운반하도록 명하셨습니다. 그런데 다윗은 블레셋 사람들이 언약궤를 수레에 실어 보낸 방식을 따라 새 수레를 준비했던 것입니다.\n\n이 사건으로 인해 다윗은 하나님을 두려워하게 되었고, 언약궤를 예루살렘으로 옮기지 못하고 가드 사람 오벧에돔의 집에 두게 됩니다. 흥미롭게도 하나님께서는 언약궤가 머문 오벧에돔의 집과 그의 모든 소유에 복을 내리셨습니다. 이는 하나님의 거룩하심과 은혜가 동시에 나타나는 모습을 보여줍니다. 하나님께서는 자신이 정하신 방법을 무시하는 것에 대해서는 엄격하시지만, 동시에 언약궤가 머무는 곳에는 풍성한 복을 내리시는 은혜로우신 분이심을 깨닫게 합니다.', E'오늘의 핵심\n다윗이 선한 의도로 언약궤를 옮기려 했지만 하나님께서 정하신 방법을 따르지 않아 비극이 일어났습니다. 하나님께서는 거룩하신 분이시며, 우리가 그분께 나아갈 때는 그분이 정하신 방법을 따라야 함을 보여줍니다.\n\n묵상 질문\n1. 선한 의도만으로는 충분하지 않다는 것을 경험한 적이 있나요?\n2. 하나님의 거룩하심을 경외하는 마음으로 예배드리고 있나요?\n3. 내 방식이 아닌 하나님의 방식을 따르기 위해 어떤 변화가 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-02', E'언약궤의 예루살렘 안치 (역대상 14장)', E'역대상 14장', E'다윗이 온 이스라엘의 왕이 되자 두로 왕 히람이 사신들과 함께 백향목과 석수, 목수들을 보내 궁전 건축을 도왔습니다. 이웃 나라의 왕이 먼저 다가와 우호적인 관계를 맺고자 한 것은 다윗 왕국이 주변국들에게도 인정받는 안정된 나라가 되었음을 보여줍니다. 다윗은 이 모든 일이 하나님께서 자신을 이스라엘의 왕으로 세우시고 백성을 위해 나라를 높이신 것임을 깨달았습니다. 왕권의 안정과 국제적 위상의 상승이 자신의 능력이 아닌 하나님의 은혜임을 분명히 인식한 것입니다.\n\n그러나 이런 평화로운 시기는 오래가지 않았습니다. 블레셋 사람들이 다윗이 온 이스라엘의 왕이 되었다는 소식을 듣고 총공세를 펼쳐 르바임 골짜기로 쳐들어왔습니다. 이전까지 다윗을 용병으로만 알았던 블레셋이 이제는 통일 이스라엘의 왕이 된 다윗을 위협으로 인식하고 선제공격을 감행한 것입니다. 다윗은 즉시 하나님께 물었습니다. "내가 블레셋 사람들을 치러 올라가리이까"(14:10). 하나님께서는 올라가라고 명하시며 그들을 다윗의 손에 넘기시겠다고 약속하셨습니다. \n\n바알브라심에서의 첫 번째 전투는 다윗의 완승으로 끝났습니다. 다윗은 하나님이 물을 쪼갬같이 대적을 흩으셨다고 고백하며 그곳을 ''바알브라심''(돌파의 주)이라 불렀습니다. 블레셋 사람들이 버리고 간 우상들은 다윗의 명령에 따라 불태워졌습니다. 하지만 블레셋은 포기하지 않고 다시 골짜기를 침범했습니다. 다윗은 또다시 하나님께 물었고, 이번에는 정면 공격이 아닌 우회 전술을 지시받았습니다. 뽕나무 꼭대기에서 걸음 소리가 들리면 그것이 하나님께서 앞서 나가시는 신호라는 것이었습니다. \n\n다윗은 하나님의 명령을 그대로 순종했고, 블레셋 군대를 기브온에서 게셀까지 완전히 격파했습니다. 이 두 번의 전투를 통해 다윗의 명성은 온 세상에 퍼졌고, 여호와께서는 모든 이방 민족이 다윗을 두려워하게 하셨습니다. 다윗의 승리는 군사적 전략이나 병력의 우세 때문이 아니라 매 순간 하나님께 묻고 그 말씀에 순종했기 때문이었습니다.', E'오늘의 핵심\n다윗은 왕권의 안정과 전쟁의 위기 앞에서 모두 하나님께 묻고 순종함으로써 승리했습니다. 하나님의 인도하심을 구하고 그 말씀에 따르는 것이 진정한 성공의 비결임을 보여줍니다.\n\n묵상 질문\n1. 성공과 번영의 때에도 하나님의 은혜를 기억하고 있나요?\n2. 위기의 순간마다 먼저 하나님께 묻는 습관이 있으신가요?\n3. 하나님의 응답이 내 생각과 다를 때에도 순종할 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-04', E'언약궤의 예루살렘 안치 (역대상 15장)', E'역대상 15장', E'다윗은 첫 번째 시도의 실패를 통해 하나님의 궤를 운반하는 것이 단순히 열심과 선한 의도만으로는 충분하지 않다는 것을 깨달았습니다. 역대상 15장은 다윗이 하나님의 규례를 따라 언약궤를 예루살렘으로 모셔오는 두 번째 시도를 보여줍니다.\n\n다윗은 먼저 자신을 위한 궁전을 세운 후 하나님의 궤를 위한 장막을 준비합니다. 그리고 "레위 사람 외에는 하나님의 궤를 멜 수 없나니"(대상 15:2)라고 선포하며, 모세의 율법에 기록된 대로 오직 레위인들만이 언약궤를 운반하도록 명령합니다. 이는 이전에 소가 끄는 수레로 운반하려 했던 실수를 바로잡는 것이었습니다.\n\n다윗은 레위의 각 가문에서 지도자들을 불러 모읍니다. 그핫, 므라리, 게르솜 자손들과 그들의 형제들 총 862명이 소집되었습니다. 다윗은 제사장들과 레위인 지도자들에게 몸을 성결하게 하고 규례대로 언약궤를 운반할 것을 명령합니다. 레위인들은 모세의 명령대로 채에 궤를 꿰어 어깨에 메었습니다.\n\n특별히 주목할 점은 다윗이 단순히 언약궤 운반에만 그치지 않고 예배를 위한 철저한 준비를 했다는 것입니다. 그는 레위인 중에서 찬양하는 자들을 세우고, 비파와 수금과 제금 등의 악기로 하나님을 찬양하게 했습니다. 헤만, 아삽, 에단을 비롯한 음악 지도자들이 임명되었고, 각각의 악기를 담당할 사람들이 배치되었습니다.\n\n언약궤가 오벧에돔의 집에서 예루살렘으로 올라올 때, 하나님께서 레위인들을 도우셨습니다. 이에 감사하여 수송아지 일곱 마리와 숫양 일곱 마리로 제사를 드렸습니다. 다윗과 모든 레위인들은 세마포 겉옷을 입고, 다윗은 베 에봇을 입었습니다. 온 이스라엘이 크게 부르며 각종 악기를 연주하며 언약궤를 모셔왔습니다.\n\n다윗이 기쁨으로 춤추며 뛰노는 모습은 하나님의 임재 앞에서 보이는 진정한 예배자의 모습이었습니다. 비록 사울의 딸 미갈은 이를 업신여겼지만, 다윗의 춤은 왕의 위엄을 내려놓고 하나님 앞에 겸손히 나아가는 참된 예배의 표현이었습니다.', E'오늘의 핵심\n하나님께서 정하신 방법대로 준비하고 순종할 때 비로소 참된 예배가 회복되며, 진정한 예배자는 자신의 체면과 위신을 내려놓고 온전히 하나님께 집중합니다.\n\n묵상 질문\n1. 내 예배와 섬김에서 하나님의 방법보다 내 방법을 앞세운 적은 없나요?\n2. 하나님 앞에서 체면이나 다른 사람의 시선을 의식하여 온전히 예배하지 못한 경험이 있나요?\n3. 오늘 하나님께서는 나의 예배 태도에 대해 무엇을 바꾸기 원하실까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-05', E'언약궤의 예루살렘 안치 (역대상 16장)', E'역대상 16장', E'다윗이 준비한 장막 안에 하나님의 언약궤가 안치되는 순간, 예루살렘은 진정한 이스라엘의 중심지가 되었습니다. 언약궤 앞에서 번제와 화목제를 드린 다윗은 백성들을 축복하며 모든 사람에게 떡과 과자를 나누어 줍니다. 이는 단순한 음식 나눔이 아니라, 하나님의 임재를 기뻐하며 온 백성이 하나 되는 언약 공동체의 모습을 보여주는 것이었습니다.\n\n다윗은 레위인들을 세워 언약궤 앞에서 섬기게 하면서 예배의 질서를 확립합니다. 아삽을 우두머리로 하여 찬양대를 조직하고, 악기를 연주하며 하나님을 찬양하게 했습니다. 특히 이날 다윗이 아삽과 그 형제들에게 부르게 한 감사의 노래는 하나님의 구원 역사를 회상하며 그분의 신실하심을 선포하는 내용이었습니다. 아브라함부터 시작된 언약의 역사, 광야에서의 보호하심, 그리고 약속의 땅에 정착하기까지의 모든 과정이 하나님의 인도하심과 은혜였음을 고백합니다.\n\n"여호와께서는 하늘을 지으셨도다"(대상 16:26)라는 선포는 이방의 우상들과 구별되는 여호와 하나님의 창조주 되심을 분명히 드러냅니다. 다윗의 찬양시는 이스라엘을 넘어 온 땅과 만국이 여호와를 찬양하도록 초대하며, 하늘과 땅, 바다와 들판, 숲의 나무들까지도 창조주 앞에서 기뻐하라고 외칩니다. 이는 하나님의 통치가 이스라엘에만 국한되지 않고 온 피조세계에 미치는 우주적 통치임을 보여줍니다.\n\n다윗은 예루살렘의 언약궤 앞에는 아삽과 그 형제들을, 기브온 산당에는 사독과 제사장들을 배치하여 두 곳에서 동시에 예배가 드려지도록 했습니다. 이는 과도기적 조치였지만, 율법에 기록된 대로 번제를 드리며 하나님을 섬기는 일에 소홀함이 없도록 한 세심한 배려였습니다. 백성들이 각자의 집으로 돌아가고 다윗도 자기 집을 축복하러 돌아가는 모습은, 공적 예배의 기쁨이 각 가정의 일상으로 이어지는 아름다운 신앙의 연속성을 보여줍니다.', E'오늘의 핵심\n다윗은 언약궤를 예루살렘에 안치하고 찬양과 제사 제도를 확립함으로써, 하나님을 중심으로 한 예배 공동체의 기초를 놓았습니다. 그의 찬양은 이스라엘의 경계를 넘어 온 피조세계가 창조주 하나님께 영광 돌리도록 초대합니다.\n\n묵상 질문\n1. 내 삶의 중심에 하나님의 임재가 자리 잡고 있나요? 어떤 영역이 아직 그분께 온전히 드려지지 않았나요?\n2. 다윗처럼 하나님의 구원 역사를 기억하며 감사하는 삶을 살고 있나요? 오늘 특별히 감사할 일은 무엇인가요?\n3. 공적 예배의 기쁨이 가정과 일상으로 이어지고 있나요? 예배와 삶이 분리되지 않으려면 어떤 노력이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-06', E'다윗의 기도와 승전기록 (역대상 1장)', E'역대상 1장', E'역대상은 아담으로부터 시작하여 포로 귀환 이후까지 이스라엘의 역사를 다시 기록한 책입니다. 특별히 1장은 아담부터 에돔의 족장들까지 이어지는 긴 족보를 통해 하나님의 구원 역사의 큰 흐름을 보여줍니다. \n\n이 족보는 단순한 이름의 나열이 아니라 하나님께서 택하신 백성의 뿌리와 정체성을 확인시켜 주는 중요한 기록입니다. 바벨론 포로에서 돌아온 이스라엘 백성들에게 이 족보는 자신들이 누구이며, 어디에서 왔는지를 상기시켜 줍니다. 특히 아담에서 노아로, 노아에서 아브라함으로, 그리고 아브라함에서 이삭과 야곱으로 이어지는 계보는 하나님의 언약이 대를 이어 신실하게 이루어져 왔음을 보여줍니다.\n\n주목할 것은 이 족보가 이스라엘뿐 아니라 주변 민족들의 계보도 함께 기록하고 있다는 점입니다. 야벳과 함의 후손들, 이스마엘과 에서의 후손들, 그리고 에돔의 왕들과 족장들까지 상세히 기록함으로써, 하나님께서는 온 인류의 역사를 주관하시는 분임을 드러냅니다. 비록 이스라엘이 선택받은 민족이지만, 하나님의 관심과 통치는 모든 민족에게 미치고 있음을 보여주는 것입니다.\n\n역대기 기자는 이러한 족보를 통해 포로 귀환 공동체에게 희망의 메시지를 전합니다. 비록 나라는 망하고 성전은 무너졌지만, 하나님의 백성으로서의 정체성은 여전히 유효하며, 조상들에게 주신 언약은 변함없이 지속되고 있다는 것입니다. 이 긴 족보의 기록은 하나님께서 역사 속에서 한 사람 한 사람을 기억하시고, 그들을 통해 구원의 계획을 이루어 가신다는 놀라운 사실을 증거합니다.', E'오늘의 핵심\n역대상의 족보는 단순한 이름의 나열이 아니라, 하나님께서 역사 속에서 신실하게 이루어 오신 구원 계획의 증거이며, 포로에서 돌아온 백성들에게 그들의 정체성과 소망을 확인시켜 주는 은혜의 기록입니다.\n\n묵상 질문\n1. 나의 신앙의 뿌리는 어디에 있으며, 하나님은 나의 가족과 공동체를 통해 어떻게 일하고 계신가요?\n2. 하나님께서 모든 민족의 역사를 주관하신다는 사실이 오늘날 우리에게 주는 의미는 무엇일까요?\n3. 어려운 시기에도 변함없는 하나님의 신실하심을 기억하며 소망을 품고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-07', E'다윗의 기도와 승전기록 (역대상 2장)', E'역대상 2장', E'역대상의 족보는 단순한 이름 나열이 아니라 하나님의 구원 역사가 어떻게 진행되어 왔는지를 보여주는 신앙의 기록입니다. 특별히 2장은 이스라엘의 열두 아들 중 유다 지파의 계보를 집중적으로 다루고 있습니다. 이는 유다 지파에서 다윗 왕이 나왔고, 궁극적으로 메시아가 오실 것이기 때문입니다.\n\n유다의 족보는 완벽하지 않은 사람들의 이야기로 가득합니다. 맏아들 에르는 여호와 보시기에 악하여 죽임을 당했고, 며느리 다말과의 관계에서 태어난 베레스가 계보를 잇습니다. 또한 아간(아갈)처럼 하나님의 명령을 어겨 이스라엘을 괴롭힌 자도 기록되어 있습니다. 이처럼 족보에는 영광스러운 이름들과 함께 실패한 이름들도 함께 기록되어 있습니다.\n\n그러나 하나님께서는 이런 불완전한 사람들을 통해서도 구원의 역사를 이루어가셨습니다. 베레스의 후손에서 보아스가 나왔고, 보아스와 룻 사이에서 오벳이 태어났으며, 오벳은 이새를 낳고, 이새는 일곱 아들과 두 딸을 두었는데 그 막내가 바로 다윗입니다. 이방 여인 룻이 다윗의 증조할머니가 된 것은 하나님의 구원이 이스라엘만이 아닌 온 세상을 향하고 있음을 보여줍니다.\n\n또한 이 족보에는 여러 여인들의 이름이 등장합니다. 고대 근동의 족보에서는 흔치 않은 일이지만, 성경은 다말, 아수바, 에브랏, 아비야 등 여인들의 이름을 기록함으로써 하나님의 구원 역사에 여성들도 중요한 역할을 담당했음을 보여줍니다. 특히 세산이 딸을 애굽 종 야르하에게 시집보낸 기록은 혈통보다 신앙이 더 중요함을 암시합니다.\n\n이 족보는 우리에게 중요한 메시지를 전합니다. 하나님께서는 완벽한 사람들이 아닌 연약하고 실패한 사람들을 통해서도 당신의 뜻을 이루어가신다는 것입니다. 우리의 과거가 어떠하든, 현재가 어떠하든, 하나님께서는 우리를 통해 새로운 역사를 써가기를 원하십니다.', E'오늘의 핵심\n하나님께서는 완벽하지 않은 사람들의 족보를 통해서도 구원의 역사를 신실하게 이루어가시며, 혈통이 아닌 믿음으로 하나님의 백성이 됨을 보여주십니다.\n\n묵상 질문\n1. 실패와 연약함이 있는 사람들도 하나님의 구원 역사에 쓰임받았다는 사실이 내게 어떤 위로를 주나요?\n2. 족보에 여성들과 이방인까지 포함된 것을 볼 때, 하나님의 구원 계획의 포용성에 대해 무엇을 깨닫게 되나요?\n3. 내 삶의 실패와 상처들도 하나님의 손에서 구원의 도구가 될 수 있다고 믿으며 기도해 볼까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-08', E'다윗의 기도와 승전기록 (역대상 3장)', E'역대상 3장', E'역대기는 바벨론 포로 귀환 이후 무너진 정체성을 회복해야 했던 이스라엘 백성에게 그들이 누구인지, 어디서 왔는지를 상기시켜 줍니다. 특히 다윗 왕가의 족보는 단순한 이름의 나열이 아니라 하나님의 언약이 역사 속에서 어떻게 이어져 왔는지를 보여주는 증거입니다.\n\n헤브론에서 태어난 여섯 아들과 예루살렘에서 태어난 아홉 아들의 명단은 다윗 왕국의 성장 과정을 그대로 반영합니다. 7년 6개월의 헤브론 통치와 33년의 예루살렘 통치 기간 동안 다윗의 가문은 크게 번성했습니다. 그러나 이 족보가 우리에게 보여주는 것은 단순한 번영의 기록만이 아닙니다. 암논과 압살롬, 아도니야와 같은 이름들은 다윗 가문 내부의 비극적인 갈등과 죄의 결과들을 떠올리게 합니다.\n\n솔로몬 이후 남유다 왕들의 계보는 다윗 왕조의 지속성을 보여줍니다. 르호보암부터 요시야까지 이어지는 왕들의 이름 속에는 신실했던 왕들과 악했던 왕들이 뒤섞여 있습니다. 아사, 여호사밧, 히스기야, 요시야와 같은 개혁의 왕들이 있었지만, 아하스와 므낫세 같은 왕들도 있었습니다. 그럼에도 하나님께서는 다윗에게 하신 약속을 신실하게 지키시며 그 왕조를 보존하셨습니다.\n\n특히 주목할 만한 것은 바벨론 포로 이후의 족보입니다. "사로잡혀 간 여고냐"로 시작되는 이 부분은 왕국의 멸망이 다윗 계보의 끝이 아님을 분명히 합니다. 스룹바벨을 비롯한 포로 귀환 공동체의 지도자들이 여전히 다윗의 후손이었다는 사실은 하나님의 약속이 가장 어두운 시기에도 살아 있었음을 증거합니다. 비록 왕관은 사라졌지만, 다윗의 혈통은 계속되었고, 이는 메시아 소망의 불씨가 꺼지지 않았음을 의미합니다.', E'오늘의 핵심\n다윗 왕가의 족보는 인간의 실패와 하나님의 신실하심이 교차하는 역사 속에서도 하나님의 언약이 끊어지지 않고 이어져 왔음을 보여줍니다.\n\n묵상 질문\n1. 다윗 가문의 영광과 실패가 공존하는 족보를 통해 하나님은 우리에게 무엇을 가르치시나요?\n2. 포로기 이후에도 계속되는 다윗의 혈통은 오늘날 우리에게 어떤 소망을 주나요?\n3. 내 삶의 실패와 연약함 속에서도 변치 않는 하나님의 신실하심을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-09', E'다윗의 기도와 승전기록 (역대상 4장)', E'역대상 4장', E'유다 지파의 확장된 족보가 펼쳐지며, 하나님께서 야곱의 예언을 통해 주신 약속이 어떻게 성취되었는지를 보여줍니다. 역대기는 왕들의 계보 이후에 유다의 남은 자손들을 기록하면서, 특별히 그들이 "왕과 함께 거주하면서 왕의 일을 하였더라"(대상 4:23)고 전합니다. 이는 창세기에서 야곱이 임종 시에 넷째 아들 유다에게 "규가 유다를 떠나지 아니하며"라고 예언한 것의 성취를 보여주는 것입니다.\n\n족보 가운데 특별히 주목할 인물은 야베스입니다. 그의 어머니는 수고로이 낳았다는 의미로 ''야베스''라는 이름을 지었지만, 그는 자신의 운명에 굴복하지 않고 하나님께 간절히 기도합니다. 복을 구하고, 지역을 넓혀달라고 하며, 환난에서 벗어나게 해달라는 그의 기도에 하나님은 응답하십니다. 이름이 주는 한계를 뛰어넘는 믿음의 기도가 얼마나 강력한지를 보여주는 장면입니다.\n\n후반부에는 시므온 지파의 족보가 이어집니다. 비록 그들이 유다 자손처럼 번성하지는 못했지만, 그들 역시 약속의 땅에서 자리를 잡고 살아갑니다. 그들은 새로운 목장을 찾아 이동하며, 때로는 적들과 싸워 승리하기도 합니다. 이 모든 과정이 하나님께서 아브라함과 이삭과 야곱에게 약속하신 땅의 성취임을 역대기는 담담하게 기록합니다.\n\n각각의 이름들과 거주지, 그들의 이동과 정착의 기록은 단순한 역사적 사실을 넘어 하나님의 신실하심을 증언합니다. 비록 북이스라엘은 이미 멸망했고, 유다도 바벨론 포로에서 돌아온 상황이지만, 역대기는 이 족보를 통해 하나님의 약속은 여전히 유효하며 그분의 백성은 계속될 것임을 선포하고 있습니다.', E'오늘의 핵심\n하나님은 야곱이 유다에게 준 예언을 신실하게 이루시며, 야베스의 기도처럼 운명을 바꾸는 믿음의 간구에 응답하시는 분이십니다.\n\n묵상 질문\n1. 내 삶의 한계와 어려움을 하나님께 내어놓고 간절히 기도한 적이 있나요?\n2. 하나님의 약속이 더디게 이루어지는 것처럼 보일 때, 어떻게 믿음을 지킬 수 있을까요?\n3. 나와 내 가정이 ''왕과 함께 거하며 왕의 일을 하는'' 삶을 산다면 어떤 모습일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-11', E'다윗의 기도와 승전기록 (역대상 5장)', E'역대상 5장', E'요단 동편에 정착한 르우벤과 갓, 므낫세 반 지파의 족보가 펼쳐집니다. 르우벤은 이스라엘의 장자였지만 아버지의 침상을 더럽힌 죄로 인해 장자의 명분을 잃었습니다. 그 명분은 요셉의 자손에게로 돌아갔고, 주권자의 지위는 유다 지파에게서 나게 되었습니다. 이는 하나님께서 죄에 대해서는 분명히 책임을 물으시면서도, 동시에 구속의 역사를 이어가시는 모습을 보여줍니다.\n\n이 세 지파는 요단 동편이라는 지리적 고립 속에서 서로 의지하며 살아갔습니다. 특히 주목할 만한 것은 그들이 하갈 사람들과 전쟁을 치를 때의 모습입니다. "그들이 싸울 때에 하나님께 의뢰하고 부르짖으므로 하나님이 그들에게 응답하셨음이라"(대상 5:20)는 기록은 전쟁의 승패가 군사력이 아닌 하나님께 대한 신뢰에 달려 있음을 증언합니다. 낙타 5만 마리, 양 25만 마리라는 엄청난 전리품은 하나님께서 주신 승리의 크기를 보여줍니다.\n\n그러나 안타깝게도 이들의 신앙은 오래가지 못했습니다. 번성하여 바산에서 헤르몬 산까지 그 영토를 넓혀갔지만, 정작 그들은 하나님이 멸하신 그 땅 백성의 신들을 섬기기 시작했습니다. 역대기는 이를 "간음하듯 섬긴지라"고 표현하며, 영적 배신의 심각성을 드러냅니다. 결국 하나님은 앗수르 왕의 마음을 일으키셔서 이들을 포로로 잡혀가게 하셨습니다.\n\n요단 동편 지파들의 역사는 우리에게 중요한 교훈을 줍니다. 위기의 때에는 하나님을 찾았지만 평안의 때에는 그분을 잊어버린 그들의 모습이 오늘 우리의 신앙을 돌아보게 합니다. 하나님의 은혜로 승리했던 그 자리에서 오히려 우상을 섬기게 된 비극은, 끊임없는 영적 각성이 필요함을 일깨워줍니다.', E'오늘의 핵심\n하나님께 의지하여 큰 승리를 거두었던 요단 동편 지파들이 번영 후에 우상숭배로 돌아서 결국 앗수르에 포로로 잡혀가는 비극적 역사를 통해, 지속적인 신앙의 중요성을 보여줍니다.\n\n묵상 질문\n1. 위기 때는 하나님을 찾다가 평안할 때 멀어지는 내 모습은 없나요?\n2. 하나님이 주신 축복과 번영이 오히려 영적 타락의 원인이 될 수 있음을 어떻게 경계할 수 있을까요?\n3. 오늘 나의 신앙이 서 있는 자리는 하나님께 부르짖던 전쟁터인가요, 아니면 우상을 섬기던 번영의 땅인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-12', E'다윗의 기도와 승전기록 (역대상 6장)', E'역대상 6장', E'역대상 6장은 레위 지파의 족보를 통해 이스라엘 신앙 공동체의 중심축을 보여줍니다. 레위의 세 아들 게르손과 그핫과 므라리로부터 시작된 이 계보는 단순한 가문의 기록을 넘어 하나님께서 이스라엘과 함께하신 은혜의 역사를 담고 있습니다.\n\n특별히 주목할 것은 아론의 후손들이 대제사장직을 이어받아 성소에서 봉사한 기록입니다. 엘르아살로부터 시작하여 비느하스, 사독을 거쳐 여호사닥에 이르는 긴 계보는 하나님의 백성을 위한 중보자의 역할이 얼마나 중요했는지를 보여줍니다. 솔로몬 성전에서 제사장 직분을 수행한 아사랴의 기록은 다윗 왕조와 제사장직이 어떻게 조화를 이루며 하나님의 나라를 섬겼는지를 증거합니다.\n\n역대기 기자는 포로기 이후 돌아온 백성들에게 레위인들의 직무를 상세히 기록함으로써 예배의 회복을 강조합니다. 헤만과 아삽, 에단으로 대표되는 찬양대의 조직은 단순한 음악 활동이 아니라 하나님께 드리는 거룩한 예배의 한 부분이었습니다. "그들의 형제 레위 사람들은 하나님의 집 장막의 모든 일을 맡았더라"(대상 6:48)는 기록처럼, 레위인들은 성전의 모든 봉사를 감당하며 이스라엘의 영적 생활을 지탱하는 기둥이 되었습니다.\n\n마지막으로 레위인들에게 주어진 48개 성읍의 목록은 하나님께서 그들을 온 이스라엘 가운데 흩어 놓으심으로써 말씀을 가르치고 백성을 돌보는 사명을 감당하게 하셨음을 보여줍니다. 땅의 기업이 없던 레위인들에게 하나님은 당신 자신이 기업이 되어주셨고, 백성들의 십일조로 그들을 부양하게 하셨습니다. 이는 하나님을 섬기는 일에 전념하는 자들을 하나님께서 친히 돌보신다는 약속의 증거입니다.', E'오늘의 핵심\n레위 지파의 족보는 하나님께서 예배와 말씀을 통해 당신의 백성과 함께하시는 은혜의 통로였으며, 포로 귀환 공동체에게 예배 회복의 청사진을 제시합니다.\n\n묵상 질문\n1. 레위인들처럼 하나님께서 내게 맡기신 고유한 사명은 무엇인가요?\n2. 예배를 섬기는 일에 나는 어떤 마음과 자세로 참여하고 있나요?\n3. 하나님을 기업으로 삼는다는 것이 오늘 내 삶에서 어떤 의미가 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-13', E'다윗의 기도와 승전기록 (역대상 7장)', E'역대상 7장', E'역대상 7장은 이스라엘 열두 지파 중 여섯 지파의 족보를 기록하고 있습니다. 잇사갈, 베냐민, 납달리, 므낫세, 에브라임, 아셀 지파의 계보와 함께 각 지파의 용사들과 그 수효가 상세히 기록되어 있는데, 이는 단순한 인구 통계가 아닌 하나님께서 각 지파와 함께하신 역사의 기록입니다.\n\n특히 주목할 것은 각 지파마다 "용감한 장사", "큰 용사", "우두머리"라는 표현이 반복되며 그들의 군사력이 구체적인 숫자로 제시된다는 점입니다. 잇사갈 지파는 8만 7천 명, 베냐민 지파는 여러 가문을 합쳐 수만 명, 아셀 지파는 2만 6천 명의 출전 가능한 군사를 보유했다고 기록합니다. 이는 포로에서 돌아온 이스라엘 백성들에게 그들의 조상이 얼마나 강성했는지를 일깨워주는 동시에, 하나님의 백성으로서의 정체성을 회복시키려는 의도를 담고 있습니다.\n\n에브라임 지파의 기록에서는 특별한 슬픔의 역사도 전해집니다. 에브라임의 아들들이 가드 사람의 짐승을 빼앗으려다 죽임을 당했고, 에브라임이 여러 날 슬퍼했다는 기록입니다. 그러나 하나님께서는 위로와 회복을 주셔서 브리아라는 아들을 다시 얻게 하셨고, 그 후손 중에서 여호수아가 나왔습니다. 재앙과 슬픔 가운데서도 하나님의 신실하신 약속은 계속되었던 것입니다.\n\n또한 여성들의 이름이 특별히 언급되는 것도 의미가 있습니다. 에브라임의 딸 세에라는 벧호론 성을 건설했고, 각 지파의 족보에는 누이들과 딸들의 이름이 기록되어 있습니다. 이는 하나님의 역사가 남성들만이 아닌 모든 백성을 통해 이루어졌음을 보여줍니다. 역대기 기자는 이 모든 기록을 통해 하나님께서 각 지파와 각 가문, 각 개인과 함께하시며 그들을 통해 당신의 뜻을 이루어가셨음을 증언하고 있습니다.', E'오늘의 핵심\n역대상 7장의 족보는 각 지파의 용사들과 그 수효를 기록하며, 하나님께서 이스라엘의 모든 지파와 함께하시며 강성하게 하셨던 역사를 보여줍니다. 슬픔과 재앙 가운데서도 하나님의 신실하신 인도하심은 계속되었습니다.\n\n묵상 질문\n1. 내 삶의 족보에는 어떤 하나님의 은혜의 흔적들이 기록되어 있나요?\n2. 에브라임처럼 슬픔의 시간을 지날 때, 하나님의 위로를 경험한 적이 있나요?\n3. 하나님께서 나를 통해 이루시려는 역사는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-14', E'다윗의 기도와 승전기록 (역대상 8장)', E'역대상 8장', E'베냐민 지파의 족보가 다시 한 번 상세히 기록되고 있습니다. 야곱의 막내아들로 태어난 베냐민은 어머니 라헬이 출산 중 숨을 거두며 낳은 아들이었습니다. 그래서 라헬은 ''베노니''(슬픔의 아들)라 이름 지었지만, 야곱은 ''베냐민''(오른손의 아들)이라 다시 명명했습니다. 이름처럼 베냐민 지파는 이스라엘 역사에서 특별한 위치를 차지하게 됩니다.\n\n본문은 베냐민의 직계 자손들부터 시작하여 각 가문의 우두머리들, 그리고 예루살렘에 거주했던 주요 인물들의 이름을 꼼꼼히 기록합니다. 특히 29절부터는 사울 왕가의 계보를 자세히 소개하는데, 이는 베냐민 지파가 이스라엘 최초의 왕을 배출했다는 역사적 의미를 강조하는 것입니다. 기브온 조상 여이엘로부터 시작하여 사울, 요나단을 거쳐 므립바알(므비보셋)에 이르는 왕가의 혈통이 이어집니다.\n\n베냐민 지파는 사사기의 비극적 사건으로 거의 멸족 위기에 처했던 아픈 과거가 있었습니다. 그러나 하나님은 그들을 버리지 않으셨고, 오히려 왕을 배출하는 영광을 허락하셨습니다. 비록 사울의 불순종으로 왕위는 유다 지파의 다윗에게 넘어갔지만, 베냐민 지파는 유다와 함께 남왕국을 형성하며 끝까지 다윗 왕가에 충성했습니다. 포로기 이후 귀환한 백성 중에도 베냐민 자손이 상당수 포함되어 있었던 것은 하나님께서 이 지파를 보존하시고 회복시키신 은혜의 증거입니다.', E'오늘의 핵심\n하나님께서는 실패와 아픔의 역사를 가진 베냐민 지파를 버리지 않으시고, 오히려 그들을 통해 이스라엘의 왕정 시대를 여는 도구로 사용하셨습니다.\n\n묵상 질문\n1. 과거의 실패나 상처가 하나님의 계획을 막을 수 없음을 믿고 있나요?\n2. 내 삶의 아픈 기억들이 하나님의 은혜로 어떻게 회복되었는지 돌아보셨나요?\n3. 하나님께서 나를 통해 이루실 새로운 역사를 기대하며 기도하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-15', E'다윗의 기도와 승전기록 (역대상 9장)', E'역대상 9장', E'바벨론 포로에서 돌아온 이스라엘 백성의 첫 거주자 명단이 역대상 9장에 기록되어 있습니다. 이 명단은 단순한 인구 조사가 아니라, 하나님께서 약속하신 회복의 증거이자 새로운 시작의 신호였습니다. 특별히 주목할 점은 예루살렘에 처음 거주한 사람들이 제사장들과 레위 사람들, 그리고 느디님 사람들이었다는 사실입니다. 느디님은 성전에서 레위인을 도와 봉사하는 사람들로서, 이들의 존재는 성전 예배가 회복의 중심에 있었음을 보여줍니다.\n\n역대기 기자는 각 지파별로 예루살렘에 거주한 사람들의 이름과 그들의 조상을 상세히 기록합니다. 유다와 베냐민 자손들, 에브라임과 므낫세 자손들이 함께 거주했다는 기록은 남북으로 갈라졌던 이스라엘이 다시 하나로 연합되기 시작했음을 암시합니다. 제사장들과 레위인들의 명단에서는 그들이 맡은 구체적인 직무까지 세세하게 기록되어 있는데, 이는 성전 봉사가 체계적으로 재정비되었음을 보여줍니다.\n\n특히 문지기들에 대한 상세한 기록이 눈에 띕니다. 212명의 문지기들이 동서남북 사방에 배치되어 성전을 지켰으며, 그들은 단순히 문을 지키는 것을 넘어 성전의 기구와 곳간을 관리하는 중요한 책임을 맡았습니다. "그들은 하나님의 성전을 맡은 직분이 있으므로 성전 주위에서 밤을 지내며 아침마다 문을 여는 책임이 그들에게 있었더라"(대상 9:27)는 기록은 그들의 헌신적인 섬김을 잘 보여줍니다. 찬양하는 레위인들은 골방에 거주하면서 주야로 찬양에 전념했다는 기록도 예배 회복의 열정을 생생하게 전해줍니다.\n\n장의 마지막 부분에서는 사울 왕의 족보가 다시 한 번 소개됩니다. 포로기 이후 왕정은 사라졌지만, 역대기 기자는 과거의 역사를 잊지 않고 기억하려 했습니다. 이는 실패한 과거조차도 하나님의 섭리 가운데 있었음을 인정하는 겸손한 역사 인식을 보여줍니다. 폐허에서 다시 일어선 공동체가 성전을 중심으로 재건되어 가는 모습은, 하나님께서 당신의 백성을 결코 버리지 않으신다는 신실하심의 증거였습니다.', E'오늘의 핵심\n포로 귀환 후 예루살렘에 정착한 사람들의 명단은 하나님께서 약속하신 회복의 실현이며, 성전 중심의 신앙 공동체가 재건되는 은혜의 기록입니다.\n\n묵상 질문\n1. 포로에서 돌아온 백성들이 가장 먼저 성전 봉사를 회복한 이유는 무엇일까요?\n2. 문지기와 찬양하는 자들처럼 맡은 직분에 충실히 헌신하는 삶을 살고 있나요?\n3. 실패와 좌절 후에도 다시 일으켜 세우시는 하나님의 은혜를 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-16', E'다윗의 기도와 승전기록 (역대상 10장)', E'역대상 10장', E'길보아 산에서 벌어진 전투는 이스라엘 역사의 한 장을 마감하는 비극적 사건이었습니다. 블레셋과의 전쟁에서 이스라엘이 패배하고 사울과 그의 세 아들이 전사한 이 사건을 역대기 저자는 단순한 군사적 패배가 아닌 영적 심판의 관점에서 조명합니다. 역대기는 사울의 죽음이 "여호와께 범죄하였기 때문"(대상 10:13)이라고 분명히 밝힙니다. 여호와의 말씀을 지키지 않고 신접한 자에게 가르침을 구했으며, 무엇보다 여호와께 묻지 않았다는 것이 그의 죄목이었습니다.\n\n사울의 최후는 참으로 비참했습니다. 블레셋의 화살에 부상을 입은 그는 할례받지 못한 자들의 모욕을 두려워하여 스스로 칼 위에 엎드러져 자결합니다. 무기를 든 자도 왕을 따라 죽고, 온 집안이 함께 몰락합니다. 블레셋 사람들은 사울의 시체를 욕되게 하여 그의 머리를 다곤 신전에 매달았습니다. 한때 이스라엘의 소망이었던 왕의 최후치고는 너무나 처참한 결말이었습니다.\n\n그러나 이 어둠 속에서도 한 줄기 빛이 있었습니다. 길르앗야베스 사람들이 목숨을 걸고 사울과 그 아들들의 시체를 수습하여 정중히 장사지낸 것입니다. 이들은 한때 사울이 자신들을 구원해 준 은혜를 잊지 않고 있었습니다. 비록 사울이 실패한 왕이었지만, 그가 행한 선한 일들은 사람들의 기억 속에 남아 있었던 것입니다.\n\n역대기는 이 비극적 사건의 결말을 하나님의 섭리로 해석합니다. "여호와께서 그를 죽이시고 그 나라를 이새의 아들 다윗에게 넘겨 주셨더라"는 구절은 역사의 주권자가 하나님이심을 분명히 보여줍니다. 하나님께서는 불순종한 왕을 심판하시는 동시에, 이미 준비하신 새로운 지도자를 통해 이스라엘의 미래를 열어가십니다. 사울의 실패는 끝이 아니라 다윗 시대를 향한 새로운 시작이었습니다.', E'오늘의 핵심\n사울의 비극적 죽음은 하나님의 말씀을 떠난 지도자의 최후를 보여주며, 동시에 하나님께서 준비하신 새로운 시대의 문을 여는 전환점이 됩니다.\n\n묵상 질문\n1. 사울이 여호와께 묻지 않고 신접한 자를 찾아간 것처럼, 나는 어려울 때 먼저 누구를 찾고 있나요?\n2. 길르앗야베스 사람들의 의로운 행동에서 우리가 배울 수 있는 은혜에 대한 태도는 무엇일까요?\n3. 내 삶에서 끝이라고 생각했던 실패가 하나님의 새로운 계획의 시작이 될 수 있음을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-18', E'다윗의 기도와 승전기록 (역대상 11장)', E'역대상 11장', E'헤브론에 모인 온 이스라엘이 다윗을 왕으로 세우는 장면은 하나님의 약속이 성취되는 감격의 순간입니다. "네가 내 백성 이스라엘의 목자가 되며 내 백성 이스라엘의 주권자가 되리라"(대상 11:2)는 하나님의 말씀이 사무엘을 통해 전해진 지 오랜 시간이 흘렀습니다. 사울의 죽음 이후 7년 반 동안 유다 지파만의 왕이었던 다윗은 이제 전 이스라엘의 왕으로 기름부음을 받습니다. 이것은 단순한 정치적 통합이 아니라 하나님의 언약이 이루어지는 거룩한 사건이었습니다.\n\n새로운 왕국의 첫 과업은 예루살렘 정복이었습니다. 여부스 족속이 "네가 이리로 들어오지 못하리라"고 호언장담했던 난공불락의 요새였지만, 다윗과 그의 용사들은 이곳을 점령합니다. 예루살렘이 ''다윗 성''이 되는 이 사건은 하나님 나라의 중심이 세워지는 의미 깊은 전환점이었습니다. 역대기는 "만군의 여호와께서 함께 계시니 다윗이 점점 강성하여 가니라"고 기록하며, 다윗의 성공이 하나님의 함께하심에서 비롯되었음을 분명히 합니다.\n\n특별히 주목할 것은 다윗과 함께한 용사들의 명단입니다. 야소브암, 엘르아살, 그리고 베들레헴 우물물을 길어온 세 용사의 이야기는 다윗이 혼자가 아니었음을 보여줍니다. 베들레헴 성문 곁 우물물을 갈망하던 다윗을 위해 목숨을 걸고 적진을 돌파한 용사들, 그리고 그 물을 차마 마시지 못하고 여호와께 부어드린 다윗의 모습은 서로를 향한 깊은 신뢰와 존중을 보여줍니다. 이어지는 긴 용사 명단은 단순한 이름의 나열이 아니라, 하나님의 나라를 세우는 일에 동참한 믿음의 사람들에 대한 기록입니다. 하나님께서는 한 사람의 영웅이 아니라 함께하는 공동체를 통해 당신의 뜻을 이루어 가십니다.', E'오늘의 핵심\n하나님의 약속대로 다윗이 온 이스라엘의 왕이 되고, 예루살렘을 정복하여 하나님 나라의 기초를 놓으며, 이 일에는 헌신된 용사들의 공동체가 함께했습니다.\n\n묵상 질문\n1. 하나님의 때를 기다리며 준비된 다윗처럼, 나는 맡겨진 자리에서 신실하게 준비하고 있나요?\n2. 다윗이 용사들의 헌신을 귀히 여긴 것처럼, 나는 함께하는 사람들의 수고와 헌신을 어떻게 존중하고 있나요?\n3. 하나님 나라를 세우는 일에 나는 어떤 마음과 자세로 동참하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-19', E'다윗의 기도와 승전기록 (역대상 12장)', E'역대상 12장', E'다윗이 사울에게 쫓겨 시글락에 숨어 있을 때, 놀라운 일이 일어났습니다. 각 지파에서 용사들이 속속 다윗에게로 모여들기 시작한 것입니다. 역대상 12장은 이들의 명단을 상세히 기록하면서, 하나님께서 어떻게 다윗을 이스라엘의 왕으로 세우셨는지를 보여줍니다.\n\n가장 먼저 온 이들은 베냐민 지파 사람들이었습니다. 사울의 동족임에도 불구하고 그들은 다윗에게로 왔습니다. 활을 다루는 데 뛰어났던 이들은 좌우 손을 자유자재로 사용하며 물매와 화살을 쏘는 용사들이었습니다. 이어서 갓 지파의 용사들이 광야의 요새로 찾아왔는데, 그들의 얼굴은 사자 같고 빠르기는 산의 사슴 같았다고 기록되어 있습니다. \n\n특별히 주목할 만한 장면은 베냐민과 유다 자손이 다윗을 찾아왔을 때의 일입니다. 다윗은 조심스럽게 그들의 의도를 확인했고, 그때 성령께서 아마새를 감싸시며 놀라운 고백을 하게 하셨습니다. "다윗이여 우리가 당신에게 속하겠고... 당신의 하나님이 당신을 도우심이니이다"(대상 12:18). 이것은 단순한 정치적 선택이 아니라 하나님의 인도하심을 확신하는 신앙고백이었습니다.\n\n므낫세, 시므온, 레위, 에브라임, 잇사갈, 스불론, 납달리, 단, 아셀, 르우벤, 갓 등 열두 지파에서 모인 용사들의 수는 실로 어마어마했습니다. 그들은 각자의 특기와 재능을 가지고 왔으며, 무엇보다 ''한 마음''으로 다윗을 왕으로 세우고자 했습니다. 역대기 저자는 이것이 하나님의 말씀을 성취하는 과정이었음을 분명히 밝히고 있습니다.\n\n헤브론에 모인 이들은 사흘 동안 함께 먹고 마시며 기뻐했습니다. 각 지파에서 풍성한 음식을 가져왔고, 온 이스라엘에 기쁨이 넘쳤습니다. 이것은 단순한 왕위 계승이 아니라, 하나님의 뜻에 순종하는 백성들이 하나로 연합되는 아름다운 모습이었습니다. 사울의 불순종으로 인한 분열과 혼란의 시대가 끝나고, 하나님 중심의 새로운 시대가 열리고 있었던 것입니다.', E'오늘의 핵심\n하나님께서는 다윗을 왕으로 세우시기 위해 각 지파의 용사들을 한 마음으로 모으셨고, 이를 통해 분열된 이스라엘을 하나로 연합시키셨습니다.\n\n묵상 질문\n1. 하나님의 뜻을 분별한 용사들이 기꺼이 다윗에게 모인 것처럼, 나는 하나님의 인도하심을 어떻게 확신하고 따르고 있나요?\n2. 사울의 동족인 베냐민 지파 사람들조차 다윗을 선택했을 때, 그들에게 필요했던 용기와 믿음은 무엇이었을까요?\n3. 서로 다른 지파가 ''한 마음''으로 연합할 수 있었던 비결은 무엇이며, 오늘 우리 공동체에는 어떤 연합이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-20', E'다윗의 기도와 승전기록 (역대상 13장)', E'역대상 13장', E'다윗이 이스라엘의 왕이 되어 가장 먼저 한 일 중 하나는 하나님의 언약궤를 예루살렘으로 모셔오는 것이었습니다. 언약궤는 하나님의 임재를 상징하는 거룩한 궤로서, 약 450년 전 광야에서 만들어진 이후 이스라엘 백성과 하나님이 만나는 장소였습니다. 그러나 사울 왕 시대에는 언약궤가 거의 잊혀졌고, 아비나답의 집에서 오랜 세월 방치되어 있었습니다.\n\n다윗은 천부장과 백부장, 그리고 온 이스라엘과 의논하여 언약궤를 옮기기로 결정합니다. "사울 때에는 우리가 궤 앞에서 묻지 아니하였느니라"(대상 13:3)는 다윗의 말은 이전 시대의 영적 무관심을 지적하면서, 새로운 시대는 하나님 중심으로 시작되어야 함을 보여줍니다. 다윗은 애굽의 시홀 시내에서부터 하맛 어귀까지 온 이스라엘을 불러모아 거국적인 행사로 준비합니다.\n\n그러나 기쁨의 행진은 비극으로 바뀝니다. 기돈의 타작마당에서 소들이 뛰자 웃사가 언약궤를 붙들었고, 하나님의 진노로 그 자리에서 죽임을 당합니다. 이 사건은 하나님의 거룩하심을 가볍게 여긴 결과였습니다. 율법에는 언약궤를 레위인이 어깨에 메고 운반하도록 명시되어 있었으나, 다윗은 블레셋 방식대로 새 수레에 실어 운반했던 것입니다. 선한 동기라 할지라도 하나님이 정하신 방법을 따르지 않으면 죽음을 불러올 수 있음을 보여주는 엄중한 경고였습니다.\n\n두려움에 사로잡힌 다윗은 언약궤를 가드 사람 오벧에돔의 집에 두고 돌아갑니다. 그런데 놀랍게도 하나님께서는 오벧에돔의 집에 복을 내리셨습니다. 이는 하나님의 임재가 징벌이 아닌 축복의 근원임을 보여줍니다. 문제는 하나님이 아니라 그분께 나아가는 우리의 자세와 방법이었던 것입니다.', E'오늘의 핵심\n하나님의 거룩하심은 선한 의도만으로는 충분하지 않으며, 그분이 정하신 방법과 질서를 따라야 함을 가르칩니다. 동시에 하나님의 임재는 두려움의 대상이면서도 축복의 근원임을 보여줍니다.\n\n묵상 질문\n1. 나는 하나님께 나아갈 때 그분의 거룩하심을 얼마나 의식하며 예배하고 있나요?\n2. 선한 목적이라도 하나님의 방법을 무시하고 내 방식대로 행한 적은 없었나요?\n3. 하나님의 임재가 내 삶에 축복이 되려면 어떤 자세가 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-21', E'다윗의 기도와 승전기록 (역대상 14장)', E'역대상 14장', E'다윗이 온 이스라엘의 왕이 된 후, 두로 왕 히람이 사신들과 백향목, 석수와 목수를 보내 궁전 건축을 돕습니다. 이웃 나라의 왕이 먼저 다가와 우호적인 관계를 맺고자 한 것은 다윗 왕국의 국제적 위상을 보여주는 증거입니다. 이때 다윗은 중요한 깨달음을 얻습니다. 자신이 왕이 된 것은 개인의 영광을 위함이 아니라 "그의 백성 이스라엘을 위하여" 하나님께서 나라를 높이 들어주신 것임을 깨닫게 됩니다.\n\n다윗이 기름부음 받아 통일 이스라엘의 왕이 되었다는 소식을 들은 블레셋은 즉시 군사 행동에 나섭니다. 사울 왕 시절부터 이스라엘을 괴롭혀온 블레셋은 다윗의 등극을 자신들의 패권에 대한 위협으로 받아들였습니다. 르바임 골짜기로 쳐들어온 블레셋 군대 앞에서 다윗이 보여준 모습은 그의 리더십의 핵심을 잘 드러냅니다. 다윗은 먼저 하나님께 물었습니다. "내가 블레셋 사람들을 치러 올라가리이까?" 하나님의 허락을 받은 후에야 전쟁에 나선 다윗은 바알브라심에서 대승을 거둡니다.\n\n블레셋이 재차 침공했을 때도 다윗은 동일하게 하나님께 묻습니다. 흥미롭게도 하나님은 이번에는 다른 전략을 주십니다. 정면 공격이 아닌 우회하여 뽕나무 수풀에서 매복하라는 것입니다. 그리고 "뽕나무 꼭대기에서 걸음 걷는 소리가 들리거든" 공격하라고 하십니다. 이는 하나님께서 먼저 앞서 나가 싸우시겠다는 약속입니다. 다윗이 하나님의 명령대로 순종했을 때, 기브온에서 게셀까지 블레셋 군대를 완전히 격파하는 대승을 거둡니다.\n\n이 두 번의 전쟁을 통해 다윗의 명성은 온 세상에 퍼졌고, 여호와께서는 모든 이방 민족이 다윗을 두려워하게 하셨습니다. 다윗의 승리는 군사력이나 전략의 우수함 때문이 아니라, 매 순간 하나님께 묻고 그분의 인도하심을 따랐기 때문입니다. 같은 적을 상대로도 상황에 따라 다른 전략을 주시는 하나님의 섬세한 인도하심이 다윗 왕국 번영의 근본이었습니다.', E'오늘의 핵심\n다윗은 왕이 된 후에도 모든 일에 하나님께 먼저 묻고 그분의 인도하심을 따랐으며, 하나님께서는 상황에 맞는 지혜와 전략을 주셔서 다윗을 승리로 이끄셨습니다.\n\n묵상 질문\n1. 중요한 결정을 앞두고 먼저 하나님께 묻는 습관이 내게 있나요?\n2. 하나님께서 나를 높여주신 이유가 무엇인지 생각해 보셨나요?\n3. 동일한 문제라도 매번 새롭게 하나님의 인도하심을 구하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-22', E'다윗의 기도와 승전기록 (역대상 15장)', E'역대상 15장', E'다윗은 첫 번째 언약궤 운반의 실패를 통해 깊은 교훈을 얻었습니다. 웃사의 죽음은 하나님께서 정하신 방법과 질서를 무시한 결과였음을 깨닫고, 이제 철저히 말씀에 따라 준비합니다. "레위 사람 외에는 하나님의 궤를 멜 수 없나니"(대상 15:2)라는 다윗의 선언은 하나님의 거룩하심 앞에서 겸손히 순종하겠다는 결단을 보여줍니다.\n\n다윗은 언약궤를 운반할 레위인들을 부족별로 소집하고, 그들에게 몸을 성결하게 할 것을 명령합니다. 단순히 외적인 준비가 아닌 영적인 준비를 강조한 것입니다. 이전의 실패를 언급하며 "우리가 규례대로 그에게 구하지 아니하였음이라"고 고백하는 다윗의 모습에서 진정한 회개와 변화를 봅니다. 레위인들은 모세의 명령대로 채에 언약궤를 꿰어 어깨에 메었습니다. 이는 하나님께서 정하신 방법을 온전히 따르는 순종의 모습입니다.\n\n특별히 주목할 것은 다윗이 찬양대를 조직한 일입니다. 헤만, 아삽, 에단을 중심으로 한 찬양대는 놋제금, 비파, 수금 등 다양한 악기로 하나님께 영광을 돌렸습니다. 언약궤를 모시는 거룩한 행렬이 단순한 이동이 아닌 하나님께 드리는 예배가 되었음을 보여줍니다. 다윗 자신도 세마포 겉옷과 베 에봇을 입고 온 백성과 함께 춤추며 기뻐했습니다.\n\n하나님께서 언약궤를 멘 레위 사람들을 도우셨다는 기록은 우리가 하나님의 뜻대로 행할 때 주시는 은혜를 보여줍니다. 첫 번째 시도와는 달리 이번에는 아무도 죽지 않았고, 오히려 기쁨과 감사의 제사를 드릴 수 있었습니다. 이는 순종이 제사보다 나음을 실제로 경험한 순간이었습니다. 사울의 딸 미갈이 다윗을 업신여긴 것과 대조적으로, 하나님은 겸손히 춤추는 다윗의 예배를 기뻐 받으셨습니다.', E'오늘의 핵심\n하나님께서 정하신 방법과 질서대로 순종할 때 참된 예배가 회복되며, 겸손한 마음으로 드리는 찬양과 경배를 하나님께서 기뻐하십니다.\n\n묵상 질문\n1. 내 예배와 섬김에서 하나님의 방법보다 내 방식을 앞세운 적은 없나요?\n2. 실패를 통해 배운 영적 교훈을 어떻게 삶에 적용하고 있나요?\n3. 다른 사람의 시선을 의식하지 않고 온전히 하나님께 집중하여 예배드리고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-23', E'다윗의 기도와 승전기록 (역대상 16장)', E'역대상 16장', E'언약궤가 예루살렘에 안치되는 날, 이스라엘의 역사에 새로운 장이 열렸습니다. 다윗이 언약궤를 위해 친 장막에 하나님의 임재를 상징하는 궤가 들어오자, 그는 번제와 화목제를 드리며 하나님께 예배했습니다. 이어서 다윗은 여호와의 이름으로 백성을 축복하고, 남녀노소 구별 없이 모든 이스라엘 백성에게 떡과 야자열매 과자, 건포도 과자를 나누어 주었습니다. 하나님의 임재가 가져온 기쁨과 축복이 온 백성에게 흘러넘친 것입니다.\n\n다윗은 단순히 일회성 축제로 그치지 않고 지속적인 예배 체계를 세웠습니다. 레위인들을 언약궤 앞에서 섬기는 자로 임명하고, 아삽을 우두머리로 하여 찬양대를 조직했습니다. 비파와 수금, 제금을 연주하며 하나님을 찬양하는 일이 정례화되었고, 제사장들은 항상 나팔을 불며 하나님의 임재를 선포했습니다. 특별히 이날 다윗은 아삽과 그 형제들을 통해 감사의 시를 하나님께 올렸는데, 이 시는 하나님의 언약적 신실하심을 기억하고 선포하는 내용으로 가득했습니다.\n\n"여호와께서는 하늘을 지으셨도다"(대상 16:26)라는 고백처럼, 다윗의 찬양은 창조주 하나님의 위대하심과 언약에 신실하신 하나님의 성품을 높였습니다. 아브라함과 이삭과 야곱에게 하신 언약을 천 대까지 기억하시는 하나님, 적은 수의 나그네였던 조상들을 보호하시고 가나안 땅으로 인도하신 하나님을 찬양했습니다. 이 찬양은 단순한 과거 회상이 아니라, 현재도 동일하게 역사하시는 하나님께 대한 신뢰의 고백이었습니다.\n\n다윗은 예배의 일상화를 위해 치밀한 조직을 갖추었습니다. 아삽과 그 형제들은 날마다 언약궤 앞에서 섬기고, 오벧에돔과 육십팔 명은 문지기로 봉사했습니다. 동시에 기브온 산당에서는 사독과 제사장들이 율법에 기록된 대로 아침저녁으로 번제를 드렸습니다. 이렇게 예루살렘의 언약궤 앞 예배와 기브온의 제사가 병행되면서, 이스라엘의 예배는 더욱 풍성해졌습니다. 온 백성이 각자의 집으로 돌아갈 때, 그들의 마음에는 하나님의 임재가 가져다준 기쁨과 평안이 가득했습니다.', E'오늘의 핵심\n다윗은 언약궤를 예루살렘에 안치하며 체계적인 예배 제도를 확립했고, 하나님의 언약적 신실하심을 찬양하는 것이 이스라엘 공동체의 중심이 되게 했습니다.\n\n묵상 질문\n1. 하나님의 임재를 경험할 때 나는 어떻게 반응하며, 그 기쁨을 다른 사람과 나누고 있나요?\n2. 매일의 예배가 형식이 아닌 살아있는 감사와 찬양이 되려면 무엇이 필요할까요?\n3. 하나님의 신실하심을 기억하고 간증하는 것이 내 신앙생활에 어떤 힘이 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-25', E'다윗의 기도와 승전기록 (역대상 17장)', E'역대상 17장', E'다윗이 평안히 왕궁에 거하며 백향목 궁전의 화려함과 언약궤가 머무는 휘장의 초라함을 대비하며 느낀 거룩한 부담감은, 성전 건축의 소원으로 이어집니다. 나단 선지자조차도 처음엔 왕의 마음을 지지했으나, 하나님께서는 의외의 응답을 주십니다. "너는 내가 거할 집을 건축하지 말라"(대상 17:4).\n\n하나님의 거절은 다윗에 대한 불만이 아니었습니다. 오히려 출애굽 이래 장막에서 장막으로, 성막에서 성막으로 함께하셨던 하나님께서는 다윗의 마음을 귀하게 여기시면서도 더 큰 계획을 품고 계셨던 것입니다. 목동이었던 다윗을 이스라엘의 주권자로 세우시고, 그와 함께하시며 대적을 물리치신 하나님께서는 이제 영원한 왕조의 약속을 주십니다.\n\n특별히 주목할 것은 다윗의 아들이 성전을 건축할 것이며, 그 왕위가 영원히 견고하리라는 약속입니다. "나는 그의 아버지가 되고 그는 나의 아들이 되리니"(대상 17:13)라는 말씀은 단순히 솔로몬을 넘어 메시아를 향한 원대한 계획을 암시합니다. 하나님께서는 다윗이 품은 일시적 소원을 영원한 약속으로 승화시키신 것입니다.\n\n이 놀라운 약속 앞에서 다윗은 겸손히 나아가 기도합니다. "나는 누구이오며 내 집은 무엇이기에"라는 그의 고백은 하나님의 은혜 앞에서 자신의 보잘것없음을 인정하는 참된 신앙인의 자세를 보여줍니다. 다윗은 자신의 계획이 거절당한 것에 실망하지 않고, 오히려 하나님께서 주신 더 큰 약속에 감사하며 그 약속이 견고히 서기를 간구합니다.', E'오늘의 핵심\n하나님께서는 다윗의 성전 건축 소원을 거절하시면서도, 그보다 더 크고 영원한 다윗 왕조의 약속을 주시며 은혜로운 계획을 펼치십니다.\n\n묵상 질문\n1. 내가 하나님을 위해 계획한 일이 거절당할 때, 그 속에서 더 큰 하나님의 뜻을 발견할 수 있나요?\n2. 다윗처럼 하나님의 은혜 앞에서 "나는 누구입니까"라고 겸손히 고백할 때가 언제였나요?\n3. 하나님께서 내게 주신 약속이 영원히 견고하도록 기도하며 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-26', E'다윗의 기도와 승전기록 (역대상 18장)', E'역대상 18장', E'다윗의 통치는 주변국들과의 전쟁으로 이어집니다. 블레셋, 모압, 아람, 에돔 등 이스라엘을 둘러싼 강대국들이 차례로 다윗 앞에 무릎을 꿇습니다. 특히 소바 왕 하닷에셀은 유브라데 강까지 자신의 세력을 확장하려는 야심을 품었지만, 다윗에게 대패하고 맙니다. 역대기 저자는 이 모든 승리의 비결을 분명히 밝혀줍니다. "다윗이 어디로 가든지 여호와께서 이기게 하시니라"(대상 18:6).\n\n전쟁에서 얻은 전리품들을 다윗이 어떻게 처리하는지 주목할 필요가 있습니다. 하닷에셀의 신하들이 가진 금 방패, 디브핫과 군에서 빼앗은 많은 놋, 하맛 왕 도우가 보낸 금과 은과 놋의 그릇들을 모두 여호와께 드립니다. 이는 승리의 영광을 자신의 것으로 삼지 않고 하나님께 돌리는 다윗의 신앙을 보여줍니다. 훗날 솔로몬이 성전 기구들을 만들 때 이 놋을 사용했다는 기록은, 다윗의 헌신이 다음 세대의 예배를 위한 준비였음을 알려줍니다.\n\n하맛 왕 도우의 반응도 흥미롭습니다. 그는 자신의 숙적이었던 하닷에셀이 다윗에게 패했다는 소식을 듣고, 아들을 보내 다윗과 우호관계를 맺으려 합니다. 이는 다윗의 승리가 단순한 군사적 정복을 넘어 주변국들에게 이스라엘의 하나님을 인정하게 만드는 계기가 되었음을 보여줍니다.\n\n역대기 저자는 다윗이 "모든 백성에게 정의와 공의를 행"했다고 기록합니다. 군사적 승리가 백성의 평안으로 이어지고, 그 평안 위에 공의로운 통치가 세워집니다. 요압, 여호사밧, 사독과 아비멜렉 등 충성스러운 신하들과 함께 다윗은 하나님께서 세우신 나라를 견고하게 다스려 나갑니다. 이 모든 것이 하나님의 인도하심과 은혜였습니다.', E'오늘의 핵심\n다윗의 모든 승리는 여호와께서 함께하심으로 가능했으며, 다윗은 전쟁의 모든 전리품을 하나님께 드림으로써 승리의 영광을 하나님께 돌렸습니다.\n\n묵상 질문\n1. 내 삶의 승리와 성취를 하나님께 온전히 돌려드리고 있나요?\n2. 다윗처럼 받은 것을 다음 세대의 예배를 위해 준비하는 마음이 있나요?\n3. 하나님이 주신 평안과 승리를 이웃을 위한 정의와 공의로 실천하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-27', E'다윗의 기도와 승전기록 (역대상 19장)', E'역대상 19장', E'다윗의 선한 의도가 오해받고 왜곡되는 일이 벌어집니다. 암몬 왕 나하스가 죽고 그의 아들 하눈이 왕위를 계승하자, 다윗은 과거 나하스가 베풀었던 호의를 기억하며 조문 사절을 보냅니다. 그러나 암몬의 방백들은 이 선의를 의심의 눈으로 바라보며 하눈에게 간언합니다. 결국 하눈은 다윗의 사절들에게 수치스러운 모욕을 가하고 돌려보냅니다.\n\n이 사건은 단순한 외교적 실례를 넘어 전쟁으로 확대됩니다. 자신들의 잘못을 깨달은 암몬 자손은 은 천 달란트라는 막대한 비용을 들여 아람의 병거와 마병을 고용합니다. 메드바 앞에 집결한 연합군의 위세는 대단했습니다. 그들은 전후방에서 이스라엘을 압박하는 전략을 구사합니다.\n\n요압은 이 위기 상황에서 지혜로운 전술과 함께 신앙의 고백을 드러냅니다. "우리가 우리 백성과 우리 하나님의 성읍들을 위하여 힘을 내자 여호와께서 선히 여기시는 대로 행하시기를 원하노라"(대상 19:13). 이는 단순히 군사적 승리를 추구하는 것이 아니라, 하나님의 백성과 하나님의 영광을 위한 싸움임을 분명히 하는 신앙 고백입니다.\n\n하나님께서는 다윗과 이스라엘에게 승리를 주십니다. 아람 군대는 도망하고, 이를 본 암몬 자손도 성읍으로 후퇴합니다. 더 많은 아람 군대가 동원되지만 결과는 마찬가지였습니다. 하닷에셀의 부하들은 결국 다윗과 화친하며, 더 이상 암몬을 돕지 않기로 결정합니다. 선의가 오해받아 시작된 전쟁이지만, 하나님께서는 이를 통해 다윗 왕국의 위상을 더욱 견고하게 세우셨습니다.', E'오늘의 핵심\n선한 의도가 오해받아 위기를 맞았지만, 하나님을 의뢰하는 신앙으로 나아갈 때 하나님께서는 그 상황을 오히려 영광의 기회로 바꾸어 주십니다.\n\n묵상 질문\n1. 내 선의가 오해받았을 때 어떻게 반응하며, 하나님께 그 상황을 맡기고 있나요?\n2. 요압처럼 위기 상황에서도 하나님의 뜻을 구하며 신앙으로 결단하고 있나요?\n3. 하나님께서 내 삶의 어려움을 통해 이루시려는 더 큰 계획은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-28', E'다윗의 기도와 승전기록 (역대상 20장)', E'역대상 20장', E'봄이 되어 왕들이 출전하는 때가 되자, 요압이 군대를 이끌고 암몬을 공격하여 수도 랍바를 포위합니다. 흥미롭게도 다윗은 예루살렘에 머물러 있었는데, 이는 사무엘하의 기록과 비교할 때 밧세바 사건이 일어난 시기와 일치합니다. 역대기 저자는 다윗의 실수를 의도적으로 생략하면서도, 그가 전쟁터에 나가지 않고 예루살렘에 머물렀다는 사실만은 기록합니다. 요압이 랍바를 함락시킨 후, 다윗은 암몬 왕의 왕관을 빼앗아 자신의 머리에 씁니다. 금 한 달란트, 약 34킬로그램에 달하는 이 왕관은 실제로 착용하기보다는 승리의 상징으로 이해됩니다. \n\n암몬과의 전쟁이 끝난 후에도 블레셋과의 전쟁은 계속됩니다. 게셀에서의 전투에서 후사 사람 십브개가 거인족의 후손 십배를 죽이고, 야일의 아들 엘하난은 골리앗의 아우 라흐미를 죽입니다. 특별히 가드에서는 손가락과 발가락이 각각 여섯 개씩인 거인이 이스라엘을 능욕하다가 다윗의 조카 요나단에게 죽임을 당합니다. 이들 거인족은 모두 다윗이 젊은 시절 물맷돌로 쓰러뜨린 골리앗과 같은 혈통이었습니다. 하나님께서는 다윗과 그의 용사들을 통해 이스라엘을 위협하던 거인족들을 완전히 제거하셨습니다. 이는 단순한 군사적 승리가 아니라, 하나님의 백성을 대적하는 모든 세력이 결국 무너질 것임을 보여주는 영적 승리의 기록입니다.', E'오늘의 핵심\n하나님께서는 다윗과 그의 용사들을 통해 이스라엘을 위협하던 모든 대적을 제거하시며, 약속의 땅에서 평안을 누리게 하십니다.\n\n묵상 질문\n1. 다윗이 전쟁터에 나가지 않고 예루살렘에 머문 것이 우리에게 주는 교훈은 무엇일까요?\n2. 반복해서 나타나는 거인족과의 전투가 의미하는 영적 교훈은 무엇일까요?\n3. 하나님께서 나의 삶 속에서 제거하기 원하시는 ''거인''은 무엇인지 기도해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-29', E'다윗의 죄악과 회개 (역대상 21장)', E'역대상 21장', E'이스라엘의 영토가 확장되고 백성의 수가 증가하는 것을 보며 다윗의 마음에 교만이 싹트기 시작합니다. 승리와 번영이 하나님의 은혜임을 잠시 잊은 다윗은 사탄의 충동에 넘어가 인구조사를 명령합니다. 요압의 간곡한 만류에도 불구하고 강행된 인구조사는 단순한 행정 행위가 아니라 하나님을 의지하기보다 군사력의 숫자를 의지하려는 불신앙의 표현이었습니다.\n\n하나님께서는 이 일을 악하게 여기셔서 이스라엘을 치시자, 다윗은 즉시 자신의 죄를 깨닫고 회개합니다. "내가 이 일을 행함으로 큰 죄를 범하였나이다"(대상 21:8)라는 다윗의 고백은 진실한 참회의 마음을 보여줍니다. 선견자 갓을 통해 전해진 세 가지 재앙 중에서 다윗은 사람의 손이 아닌 하나님의 손에 자신을 맡기기를 택합니다. 이는 하나님의 긍휼하심을 신뢰하는 믿음의 표현이었습니다.\n\n전염병으로 칠만 명이 죽는 참혹한 재앙 가운데서도 하나님의 긍휼은 계속됩니다. 예루살렘을 멸하려던 천사를 보신 하나님께서 재앙을 뉘우치시고 멈추게 하신 것입니다. 다윗은 굵은 베를 입고 엎드려 백성의 죄를 자신이 대신 담당하기를 간구합니다. 이러한 중보자적 기도는 메시아를 예표하는 모습이기도 합니다.\n\n오르난의 타작마당에서 제단을 쌓으라는 하나님의 명령에 다윗은 즉시 순종합니다. 오르난이 무료로 드리겠다는 제안을 거절하고 정당한 값을 치른 다윗의 모습은 하나님께 드리는 예배의 진정성을 보여줍니다. 번제와 화목제를 드린 다윗에게 하나님께서는 하늘에서 불을 내려 응답하심으로써 용서와 화해의 메시지를 전하십니다. 이 장소는 훗날 솔로몬이 성전을 건축하게 될 거룩한 터가 됩니다.', E'오늘의 핵심\n하나님의 은혜를 자신의 공로로 착각한 다윗의 교만은 큰 재앙을 불러왔지만, 즉각적인 회개와 중보기도를 통해 하나님의 긍휼하심을 경험하게 됩니다.\n\n묵상 질문\n1. 내 삶의 성취와 성공을 하나님의 은혜가 아닌 내 능력으로 여긴 적은 없나요?\n2. 다윗처럼 잘못을 깨달았을 때 즉시 돌이켜 회개하는 마음의 준비가 되어 있나요?\n3. 값없이 드리는 예배가 아닌 희생이 따르는 진정한 예배를 드리고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-12-30', E'다윗의 죄악과 회개 (역대상 22장)', E'역대상 22장', E'다윗은 하나님께서 심판을 멈추신 오르난의 타작 마당이 바로 성전이 세워질 곳임을 깨닫고 선포합니다. "이는 여호와 하나님의 성전이요 이는 이스라엘의 번제단이라"(대상 22:1). 자신의 교만으로 인해 백성들이 고통받은 바로 그곳이 하나님과 백성이 만나는 은혜의 장소가 될 것임을 알게 된 것입니다.\n\n다윗은 비록 자신이 직접 성전을 건축할 수 없지만, 아들 솔로몬이 그 일을 완수할 수 있도록 온 힘을 다해 준비합니다. 금 십만 달란트와 은 백만 달란트, 그리고 무게를 달 수 없을 만큼의 놋과 철, 백향목과 돌들을 모으는 다윗의 모습에서 우리는 하나님의 집을 향한 그의 뜨거운 사랑을 봅니다. 전쟁으로 많은 피를 흘린 자신은 평화의 성전을 건축할 수 없다는 하나님의 뜻을 겸허히 받아들이면서도, 다음 세대가 그 일을 감당할 수 있도록 최선을 다하는 것입니다.\n\n솔로몬에게 전하는 다윗의 당부는 단순히 건축 기술이나 재정에 관한 것이 아니었습니다. "여호와께서 네게 지혜와 총명을 주사 네게 이스라엘을 다스리게 하시고 네 하나님 여호와의 율법을 지키게 하시기를 더욱 원하노라"라는 그의 말에는 성전 건축보다 더 중요한 것이 하나님의 말씀을 따라 살아가는 삶임을 가르치는 아버지의 마음이 담겨 있습니다. 또한 이스라엘의 모든 방백들에게도 솔로몬을 도울 것을 명하며, 먼저 "마음과 뜻을 바쳐서 너희 하나님 여호와를 구하라"고 권면합니다. 성전 건축은 단지 건물을 세우는 일이 아니라 온 백성이 하나님께 마음을 드리는 영적인 사역임을 보여주고 있는 것입니다.', E'오늘의 핵심\n다윗은 자신이 성전을 건축할 수 없다는 하나님의 뜻을 겸허히 받아들이고, 아들 솔로몬과 백성들이 그 사명을 완수할 수 있도록 물질과 마음을 다해 준비합니다.\n\n묵상 질문\n1. 다윗처럼 다음 세대를 위해 내가 준비하고 있는 것은 무엇인가요?\n2. 하나님의 일을 위해 "환난 중에도" 최선을 다했던 다윗의 헌신이 나에게 주는 도전은 무엇인가요?\n3. 성전 건축보다 먼저 "마음과 뜻을 바쳐 하나님을 구하라"는 다윗의 권면을 오늘 나는 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-01', E'솔로몬의 성전 건축', E'역대하 1장', E'솔로몬이 왕위에 오른 뒤 가장 먼저 한 일은 온 이스라엘의 지도자들과 함께 기브온 산당으로 올라가 하나님께 천 마리 번제를 드린 것이었습니다. 왕으로서 해야 할 일이 산더미처럼 쌓여 있었을 텐데, 그는 정치적 기반을 다지거나 군사력을 강화하는 일보다 하나님 앞에 나아가는 것을 최우선 순위에 놓았습니다. 이 모습에서 우리는 삶의 새로운 시작점에서 무엇을 먼저 붙잡아야 하는지를 배우게 됩니다.\n\n그날 밤 하나님께서 직접 나타나셔서 "무엇을 주랴, 구하라"고 말씀하셨을 때, 솔로몬의 대답은 놀라웠습니다. 그는 부도, 영광도, 원수의 멸망도, 장수도 구하지 않았습니다. 대신 "이렇게 많은 주의 백성을 누가 능히 재판하리이까"라고 고백하며 지혜와 지식을 구했습니다. 이 기도에는 두 가지가 담겨 있습니다. 하나는 자신의 부족함에 대한 솔직한 인정이고, 다른 하나는 자기에게 맡겨진 백성을 향한 책임 의식입니다. 솔로몬은 왕의 자리가 자기 영달을 위한 것이 아니라 하나님의 백성을 섬기기 위해 주어진 것임을 알고 있었습니다.\n\n하나님은 그 마음을 기뻐하셔서 지혜와 지식뿐 아니라 구하지 않은 부와 재물과 영광까지 더해 주셨습니다. 이것은 회막 중심의 시대에서 성전 중심의 시대로 나아가는 위대한 전환의 출발점이었습니다. 다윗이 기초를 닦아 둔 하나님 중심의 신앙 공동체를 솔로몬이 이어받아 더욱 견고하게 세워 가는 첫걸음이, 바로 이 겸손한 기도에서 시작된 것입니다.\n\n우리에게도 새 학기, 새 직장, 새로운 관계처럼 낯선 출발선에 서는 순간이 찾아옵니다. 그때 가장 먼저 무엇을 구하십니까? 성공이나 인정보다 먼저, 내게 맡겨진 자리에서 하나님의 뜻을 분별할 지혜를 구하는 것이 솔로몬이 보여 준 첫걸음입니다. 오늘 내가 서 있는 자리에서 가장 먼저 하나님께 구해야 할 것은 무엇인지 조용히 여쭈어 보시길 바랍니다.', E'오늘의 핵심\n다윗에 의해 다져진 나라의 기틀과 국가적 리더십이 솔로몬으로 이어지고, 하나님의 성전을 건축하는 위대한 역사가 진행됩니다.\n\n묵상 질문\n하나님은 왜 솔로몬에게 성전 건축의 사명을 주셨을까요?\n나도 하나님 중심으로 내 삶의 기초를 단단히 세우고 있나요?\n솔로몬처럼 주어진 사명을 충실히 이루기 위해 기도하겠다는 결단이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-02', E'솔로몬의 성전 낙성식 (역대하 5장)', E'역대하 5장', E'솔로몬이 성전 건축의 모든 일을 마치고, 아버지 다윗이 드린 은과 금과 모든 기구를 하나님의 전 곳간에 두었습니다. 이제 마지막 남은 일은 여호와의 언약궤를 다윗 성에서 새로 지은 성전으로 옮기는 것이었습니다. 솔로몬은 이스라엘의 모든 장로들과 지파의 우두머리들, 족장들을 예루살렘으로 소집합니다. 일곱째 달 초막절에 온 백성이 함께 모여 이 역사적인 순간을 목격하게 됩니다.\n\n레위인 제사장들이 언약궤를 메고 올라갈 때, 솔로몬 왕과 온 이스라엘 회중은 셀 수 없이 많은 양과 소로 제사를 드렸습니다. 이는 단순한 종교 의식이 아니라 하나님의 임재를 모시는 거룩한 순간에 대한 백성들의 경외심과 감사의 표현이었습니다. 제사장들은 언약궤를 지성소 그룹들의 날개 아래 안치했고, 그 안에는 모세가 호렙 산에서 받은 두 돌판이 들어 있었습니다. 이 돌판은 하나님께서 이스라엘과 맺으신 언약의 증거였습니다.\n\n성전 봉헌의 절정은 찬양과 함께 임했습니다. 아삽과 헤만과 여두둔을 비롯한 레위인 찬양대가 세마포를 입고 제단 동쪽에 서서 악기를 연주하고, 백이십 명의 제사장이 나팔을 불었습니다. 그들이 일제히 소리를 높여 "선하시도다 그의 자비하심이 영원히 있도다"라고 찬송할 때, 놀라운 일이 일어났습니다. 여호와의 전에 구름이 가득 찼고, 제사장들은 그 구름으로 인해 서서 섬길 수 없을 정도였습니다. 이는 출애굽 때 성막을 가득 채웠던 하나님의 영광이 이제 예루살렘 성전에 임한 것입니다. 하나님께서는 솔로몬의 성전을 자신의 거처로 받아주신 것입니다.', E'오늘의 핵심\n언약궤가 성전에 안치되고 온 백성이 하나를 되어 찬양할 때, 하나님의 영광이 구름으로 성전에 가득 차서 하나님께서 그 성전을 받으셨음을 보여주셨습니다.\n\n묵상 질문\n1. 우리가 한마음으로 하나님을 찬양할 때 어떤 일이 일어날 수 있을까요?\n2. 하나님의 임재를 경험하기 위해 내가 준비해야 할 것은 무엇일까요?\n3. 내 삶의 성전에 하나님의 영광이 머물기를 간절히 사모하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-03', E'솔로몬의 성전 낙성식 (역대하 6장)', E'역대하 6장', E'솔로몬이 성전 건축을 완성하고 언약궤를 지성소에 안치한 후, 이제 본격적인 성전 봉헌 기도를 드립니다. 백성들 앞에 서서 축복을 선포한 솔로몬은 다윗에게 주신 하나님의 약속이 성취되었음을 고백합니다. 하나님께서는 예루살렘을 택하여 당신의 이름을 두시고, 다윗을 택하여 백성을 다스리게 하셨으며, 그 아들을 통해 성전을 건축하게 하신 것입니다.\n\n솔로몬의 기도는 놋으로 만든 대 위에서 무릎을 꿇고 하늘을 향해 손을 펴고 드리는 간절한 모습으로 시작됩니다. "천지에 주와 같은 신이 없나이다"라는 고백으로 시작된 기도는 하나님의 신실하심과 언약의 성취를 찬양하며, 동시에 무한하신 하나님께서 유한한 성전에 거하실 수 있겠느냐는 겸손한 물음을 담고 있습니다.\n\n이어지는 솔로몬의 기도는 일곱 가지 상황에서 이스라엘 백성이 성전을 향해 기도할 때 응답해 주시기를 간구하는 내용입니다. 재판에서의 정의 실현, 전쟁에서의 패배, 가뭄, 기근과 전염병, 포로 됨, 그리고 모든 재앙과 고통의 때에 이 성전을 향해 기도하면 하늘에서 들으시고 용서하시며 회복시켜 주시기를 구합니다. 특별히 주목할 것은 솔로몬이 이방인들을 위해서도 기도한다는 점입니다. "주의 백성 이스라엘에 속하지 않은 이방인"이 하나님의 이름을 위하여 멀리서 와서 기도할 때도 들어주시기를 간구합니다.\n\n솔로몬의 기도는 성전이 단순한 건물이 아니라 하나님과 백성이 만나는 은혜의 장소임을 보여줍니다. 하나님께서는 하늘과 하늘들의 하늘이라도 용납할 수 없는 무한하신 분이시지만, 당신의 이름을 두신 이 성전을 향한 백성의 기도를 들으시고 응답하시는 자비로운 분이십니다. 이것은 오늘날 그리스도의 몸 된 교회와 성도들에게도 동일하게 적용되는 은혜의 원리입니다.', E'오늘의 핵심\n솔로몬은 성전 봉헌 기도를 통해 하나님의 무한하심과 자비하심을 고백하며, 이 성전이 모든 백성이 회개하고 돌아와 은혜를 받는 기도의 집이 되기를 간구합니다.\n\n묵상 질문\n1. 솔로몬처럼 하나님의 위대하심을 인정하면서도 친밀하게 기도할 수 있나요?\n2. 내가 어려움에 처했을 때 하나님께 돌아와 기도하고 있나요?\n3. 나의 기도가 나만을 위한 것인지, 아니면 이웃과 열방을 품고 있는지 돌아봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-04', E'솔로몬의 성전 낙성식 (역대하 7장)', E'역대하 7장', E'솔로몬의 기도가 끝나자마자 하늘에서 불이 내려와 번제물과 제물들을 사르고, 여호와의 영광이 성전에 가득 찼습니다. 이는 하나님께서 솔로몬의 기도를 기쁘게 받으셨다는 분명한 표징이었습니다. 제사장들조차 여호와의 영광으로 인해 성전에 들어갈 수 없을 정도였습니다. 이스라엘 백성들은 하늘에서 내린 불과 성전 위에 머무는 여호와의 영광을 목격하고는 돌을 깐 땅에 엎드려 경배하며 "선하시도다 그의 인자하심이 영원하도다"라고 찬양했습니다.\n\n성전 낙성식은 장엄하게 거행되었습니다. 솔로몬 왕이 드린 제물만 해도 소 이만 이천 마리, 양 십이만 마리에 달했습니다. 제사장들과 레위인들은 각자의 직분대로 서서 섬겼고, 다윗이 만든 악기로 여호와의 인자하심을 찬송했습니다. 칠 일 동안의 제단 낙성식과 칠 일 동안의 초막절이 이어졌으며, 하맛 어귀에서부터 애굽 강까지 온 이스라엘이 모여 함께 기뻐했습니다.\n\n밤에 여호와께서 솔로몬에게 나타나셔서 중요한 약속을 주셨습니다. 하나님은 이 성전을 택하여 제사하는 집으로 삼으셨고, "내 이름으로 일컫는 내 백성이 그들의 악한 길에서 떠나 스스로 낮추고 기도하여 내 얼굴을 찾으면 내가 하늘에서 듣고 그들의 죄를 사하고 그들의 땅을 고칠지라"(대하 7:14)고 약속하셨습니다. 이것은 단순히 건물로서의 성전이 아니라, 회개와 회복의 장소로서 성전의 영적 의미를 보여주는 것입니다.\n\n하지만 하나님의 약속에는 엄중한 경고도 담겨 있었습니다. 만일 이스라엘이 하나님을 버리고 다른 신들을 섬긴다면, 이 거룩한 성전조차도 버림받아 모든 민족 중에 속담거리가 될 것이라는 경고였습니다. 하나님의 임재와 영광은 결코 당연한 것이 아니며, 백성들의 신실한 순종과 함께할 때만 지속된다는 것을 분명히 하신 것입니다.', E'오늘의 핵심\n하나님께서는 솔로몬의 기도에 불과 영광으로 응답하시고, 성전을 회개와 회복의 장소로 삼으시면서도 순종하지 않으면 버리실 것을 엄중히 경고하십니다.\n\n묵상 질문\n1. 하나님께서 나의 기도에 응답하신 경험이 있다면 어떻게 그 은혜를 기억하고 있나요?\n2. "스스로 낮추고 기도하여 내 얼굴을 찾으면"이라는 말씀이 오늘 나에게 주는 도전은 무엇인가요?\n3. 하나님의 임재를 지속적으로 경험하기 위해 내가 버려야 할 것과 지켜야 할 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-05', E'솔로몬의 업적', E'역대하 8장', E'이스라엘의 번영은 다윗이 닦아두었던 기반을 바탕으로 솔로몬 시대에 정점에 이릅니다. 찬란한 영광으로 가득한 성전이 지어지고 그곳에서 이루어지는 모든 행사가 하나님 앞에서 정결하게 진행되었습니다. 역대하 9장에 나오는 스바 여왕의 이스라엘 방문은 솔로몬의 최전성기를 보여주는 사건입니다. 이스라엘 역사 중 최고의 전성기를 꽃피운 바로 이 시대가 언제까지나 이어졌다면, 더 바랄 나위가 없었을 것입니다. 이 바람은 어느 누구보다도 하나님께서 더욱 간절히 원하시는 것이었습니다. 하지만 이처럼 화려한 모습 너머에는 솔로몬이 이방 여인들을 아내로 맞이하는 등 국가의 기반을 흔들게 될 문제들이 점차 싹을 틔우고 있었습니다.\n역대하에는 자세한 기록이 실려 있지 않지만 앞서 열왕기상에서 살펴본 솔로몬을 볼 때 하나님을 향한 솔로몬의 마음은 처음과 나중이 같지 않았습니다. 하나님께서 허락하신 부귀영화를 누리면서 점차 그의 마음이 하나님을 떠났던 것입니다. 솔로몬은 말년에 하나님의 은혜로 하나님을 경외하는 인생만이 참되다는 것을 깨닫지만, 그의 아들 르호보암에게는 그가 되찾은 신앙이 이어지지 못합니다.', E'오늘의 핵심\n하나님께 지혜를 선물 받고 아버지로부터 튼튼한 국기를 물려받은 솔로몬은 선대의 신앙과 제도를 계승하여 많은 업적을 남깁니다.\n\n묵상 질문\n1. 하나님은 번영과 축복 가운데서도 우리의 신앙을 지키길 원하시지 않을까요?\n2. 나는 지금 가장 잘 나가는 순간에도 하나님과의 관계를 소홀히 하고 있지는 않나요?\n3. 솔로몬처럼 번영의 유혹 속에서도 주를 향한 내 마음이 흔들리지 않도록 기도하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-06', E'남유다 왕국의 초기 왕들 (역대하 14장)', E'역대하 14장', E'남유다의 3대 왕 아사의 통치가 시작됩니다. 아비야의 뒤를 이어 왕위에 오른 아사는 하나님 보시기에 선과 정의를 행하는 왕이었습니다. 그가 가장 먼저 착수한 일은 종교개혁이었습니다. 이방 제단과 산당을 없애고, 주상을 깨뜨리며, 아세라 상을 찍어버렸습니다. 더 나아가 유다 백성들에게 여호와 하나님을 찾고 그분의 율법과 명령을 행하도록 명령했습니다. 이러한 개혁의 결과는 놀라웠습니다. 10년 동안 전쟁이 없는 평안의 시대가 열린 것입니다.\n\n아사는 이 평화의 시간을 허투루 보내지 않았습니다. 견고한 성읍들을 건축하며 국방을 강화했고, 유다와 베냐민 지파에서 58만 명의 정예 군대를 조직했습니다. 그의 이러한 준비는 하나님을 향한 신뢰에 기반을 둔 것이었습니다. "우리가 우리 하나님 여호와를 찾았으므로 이 땅이 아직 우리 앞에 있나니"라는 그의 고백은 평안의 근원이 하나님께 있음을 분명히 보여줍니다.\n\n그러나 이 평화는 곧 시험을 맞게 됩니다. 구스 사람 세라가 백만 대군과 병거 삼백 대를 이끌고 침공해 온 것입니다. 58만 대 100만이라는 압도적인 수적 열세 앞에서 아사의 진정한 신앙이 드러납니다. 그는 군사력이나 전략이 아닌 하나님께 부르짖었습니다. "여호와여 힘이 강한 자와 약한 자 사이에는 주밖에 도와 줄 이가 없사오니"라는 그의 기도는 절대적인 하나님 의존을 보여줍니다. 하나님께서는 이 기도에 응답하셔서 구스 군대를 완전히 패배시키셨고, 남유다는 큰 승리와 함께 많은 전리품을 얻게 되었습니다. 아사의 개혁과 신앙은 단순한 종교적 행위가 아니라 국가의 운명을 좌우하는 실제적인 능력이었음을 보여주는 것입니다.', E'오늘의 핵심\n아사 왕은 철저한 종교개혁을 통해 10년간의 평화를 누렸고, 백만 대군의 위협 앞에서도 오직 하나님만을 의지함으로써 놀라운 승리를 경험했습니다.\n\n묵상 질문\n1. 내 삶에서 제거해야 할 ''이방 제단과 산당''은 무엇이며, 그것들이 나의 영적 평안을 어떻게 방해하고 있나요?\n2. 평안한 시기에도 영적으로 게으르지 않고 ''견고한 성읍''을 쌓듯 신앙의 기초를 다지고 있나요?\n3. 압도적인 어려움 앞에서 나는 무엇을 의지하며, 아사처럼 "주밖에 도와줄 이가 없다"는 고백을 할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-08', E'남유다 왕국의 초기 왕들 (역대하 15장)', E'역대하 15장', E'하나님의 영이 오뎃의 아들 아사랴에게 임하자, 그는 아사 왕에게 나아가 중요한 메시지를 전합니다. "너희가 여호와와 함께 하면 여호와께서 너희와 함께 하실지라"는 이 선언은 하나님과 그의 백성 사이의 언약 관계를 명확히 보여줍니다. 아사랴는 이스라엘의 과거를 돌아보며, 참 신도 없고 가르치는 제사장도 없고 율법도 없던 어두운 시절을 상기시킵니다. 그러나 환난 가운데서 하나님을 찾았을 때 하나님께서 그들과 만나주셨다는 역사의 교훈을 전하며, 현재의 아사와 유다 백성들에게 용기를 북돋웁니다.\n\n아사랴의 예언을 들은 아사는 즉시 행동에 나섭니다. 유다와 베냐민 온 땅에서 우상을 제거하고, 에브라임 산지에서 빼앗은 성읍들에서도 가증한 것들을 없앴으며, 여호와의 제단을 재건합니다. 그의 개혁은 단순한 종교 정책을 넘어 백성들의 마음을 하나로 모으는 결과를 가져왔습니다. 북이스라엘에서도 많은 사람들이 여호와께서 아사와 함께하심을 보고 유다로 내려왔습니다.\n\n특별히 주목할 점은 아사 왕 15년 3월에 있었던 언약 갱신입니다. 백성들은 마음을 다하고 목숨을 다하여 여호와를 찾기로 언약했고, 큰 소리로 외치며 피리와 나팔을 불어 여호와께 맹세했습니다. 이는 형식적인 의례가 아닌 진심 어린 헌신의 표현이었습니다. 그 결과 하나님께서는 그들을 만나주시고 사방에 평안을 주셨습니다.\n\n아사의 개혁은 개인적인 차원에서도 철저했습니다. 그는 어머니 마아가가 아세라 우상을 만들자 태후의 자리에서 폐위시키고 그 우상을 기드론 시내에서 불태워버렸습니다. 가족 관계보다 하나님께 대한 충성을 우선시한 것입니다. 비록 산당을 완전히 제거하지는 못했지만, 아사의 마음은 일평생 하나님께 온전히 향했습니다. 이러한 신실함의 결과로 35년까지 전쟁이 없는 평화의 시대가 지속되었습니다.', E'오늘의 핵심\n아사랴의 예언을 듣고 아사가 단행한 종교개혁은 백성들의 진심 어린 언약 갱신으로 이어졌고, 하나님께서는 그들과 만나주시며 평안으로 응답하셨습니다.\n\n묵상 질문\n1. 하나님과 함께하는 삶과 그분을 떠난 삶의 차이를 경험하신 적이 있나요?\n2. 가족이나 친한 관계보다 하나님을 우선시해야 할 때 어떤 결단이 필요할까요?\n3. 내 삶에서 제거해야 할 ''우상''이 있다면 무엇이며, 어떻게 행동하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-09', E'남유다 왕국의 초기 왕들 (역대하 16장)', E'역대하 16장', E'아사 왕의 통치 36년, 북이스라엘의 바아사가 라마를 요새화하여 남유다를 압박해 왔습니다. 이전 구스와의 전쟁에서 하나님만을 의지하여 큰 승리를 거두었던 아사였지만, 이번에는 전혀 다른 선택을 합니다. 그는 성전과 왕궁의 금은을 꺼내어 아람 왕 벤하닷에게 보내며 군사동맹을 요청했습니다. 눈앞의 위기를 인간적 방법으로 해결하려 한 것입니다. \n\n실제로 이 전략은 즉각적인 효과를 보였습니다. 아람군이 북이스라엘의 여러 성읍을 공격하자 바아사는 라마 건축을 포기할 수밖에 없었고, 아사는 그 건축 자재들을 가져와 게바와 미스바를 건축하는 데 사용했습니다. 겉보기에는 성공적인 외교와 군사 전략이었습니다.\n\n그러나 하나님의 관점은 달랐습니다. 선견자 하나니가 아사를 찾아와 준엄한 책망을 전합니다. "여호와의 눈은 온 땅을 두루 감찰하사 전심으로 자기에게 향하는 자들을 위하여 능력을 베푸시나니"(대하 16:9)라는 말씀과 함께, 하나님을 의지하지 않은 불신앙을 지적했습니다. 과거 구스와의 전쟁을 상기시키며, 하나님을 의지했을 때 주셨던 승리와 대조되는 현재의 모습을 드러낸 것입니다.\n\n더욱 안타까운 것은 아사의 반응이었습니다. 그는 하나님의 책망을 겸허히 받아들이는 대신 오히려 선견자를 옥에 가두고, 백성들 중 일부를 학대하기까지 했습니다. 신앙의 연륜이 쌓일수록 더욱 겸손해져야 할 왕이 오히려 교만해진 것입니다. \n\n아사의 말년은 더욱 비극적이었습니다. 발병으로 고통받으면서도 여호와께 구하지 않고 의원들에게만 의지했다는 기록은, 한때 하나님께 충성했던 왕의 영적 쇠퇴를 보여줍니다. 41년간의 통치를 마감하며 성대한 장례를 치렀지만, 그의 말년은 믿음의 후퇴라는 아쉬움을 남겼습니다.', E'오늘의 핵심\n신앙의 절정기를 경험했던 아사 왕이 통치 말년에는 하나님보다 인간적 방법을 의지하며, 하나님의 책망마저 거부하는 영적 쇠퇴의 길을 걸었습니다.\n\n묵상 질문\n1. 과거의 믿음의 승리가 현재의 신앙을 보장하지 않는다는 사실을 어떻게 받아들이시나요?\n2. 위기 상황에서 나는 먼저 하나님께 나아가나요, 아니면 인간적 해결책을 찾나요?\n3. 하나님의 책망을 들을 때 내 마음은 얼마나 열려 있는지 점검해 보셨습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-10', E'남유다 왕국의 초기 왕들 (역대하 17장)', E'역대하 17장', E'아사 왕의 뒤를 이어 왕위에 오른 여호사밧은 아버지가 닦아놓은 신앙의 기초 위에 더욱 견고한 나라를 세워갑니다. 역대기 저자는 여호사밧이 "그의 조상 다윗의 처음 길로 행하여 바알들에게 구하지 아니하고"(대하 17:3) 걸었다고 기록함으로써, 그가 진정한 다윗의 후계자임을 보여줍니다. \n\n여호사밧의 통치가 특별했던 것은 단순한 군사력 강화나 정치적 안정에 머물지 않고 백성들의 영적 개혁에 힘썼다는 점입니다. 왕위 3년에 그는 방백들과 레위인들, 제사장들을 유다 전역에 파송하여 하나님의 율법을 가르치게 합니다. 이는 단순한 종교 교육이 아니라 국가적 차원의 신앙 부흥 운동이었습니다. 왕과 지도자들뿐 아니라 모든 백성이 하나님의 말씀을 알고 그 말씀대로 살아가는 것이 진정한 국가의 힘이라는 확신에서 비롯된 정책이었습니다.\n\n하나님께서는 말씀 중심의 개혁을 단행한 여호사밧에게 놀라운 축복으로 응답하십니다. 주변 나라들이 유다를 두려워하여 전쟁을 일으키지 못했고, 오히려 블레셋과 아라비아 사람들이 조공과 예물을 바쳤습니다. 이는 군사력이나 외교 수완이 아닌, 하나님께서 주시는 평화였습니다. 여호사밧이 "전심으로 여호와의 길"을 걸었을 때, 하나님께서 나라를 견고하게 하시고 부귀와 영광을 더하신 것입니다.\n\n특히 주목할 점은 여호사밧이 강대해진 후에도 교만하지 않고 계속해서 하나님 중심의 통치를 이어갔다는 사실입니다. 그는 예루살렘과 유다 전역에 견고한 요새를 건축하고 강력한 군대를 조직했지만, 이 모든 것이 하나님의 축복임을 잊지 않았습니다. 아버지 아사가 말년에 하나님보다 인간적인 동맹을 의지했던 실수를 반면교사로 삼아, 여호사밧은 끝까지 하나님께 충성했습니다.', E'오늘의 핵심\n여호사밧은 군사력 강화보다 백성들에게 하나님의 말씀을 가르치는 일을 우선시했고, 하나님께서는 이러한 말씀 중심의 개혁에 평화와 번영으로 응답하셨습니다.\n\n묵상 질문\n1. 여호사밧이 왕위 초기에 가장 먼저 한 일이 말씀 교육이었던 이유는 무엇일까요?\n2. 내 삶의 우선순위에서 하나님의 말씀을 아는 것과 실천하는 것이 어느 위치에 있나요?\n3. 하나님께서 주신 축복과 성공 앞에서도 겸손을 유지할 수 있는 비결은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-11', E'요아스와 여호야다의 개혁 (역대하 23장)', E'역대하 23장', E'여섯 해 동안 남유다는 아합과 이세벨의 딸 아달랴의 통치 아래서 우상숭배의 어둠에 빠져 있었습니다. 바알 숭배가 성행하고 다윗 왕가의 전통이 무너져가던 그때, 하나님께서는 제사장 여호야다를 통해 놀라운 개혁의 역사를 준비하고 계셨습니다. 여호야다는 아달랴의 학살에서 살아남은 어린 요아스를 6년간 성전에서 숨겨 키우며 때를 기다렸고, 마침내 제칠년에 용기를 내어 거사를 일으킵니다.\n\n여호야다의 개혁은 철저히 준비되고 질서 있게 진행되었습니다. 그는 먼저 백부장들과 언약을 맺고, 레위인들과 이스라엘 족장들을 모아 하나님의 전에서 왕과 언약을 세웁니다. 제사장들과 레위인들을 3분의 1씩 나누어 성전 문과 왕궁, 기초문을 지키게 하는 치밀한 계획은 이 일이 단순한 정변이 아니라 하나님의 거룩한 질서를 회복하는 신앙개혁임을 보여줍니다.\n\n요아스에게 면류관을 씌우고 율법책을 주는 대관식 장면은 의미심장합니다. 왕이 율법책을 받는다는 것은 그가 하나님의 말씀 아래서 통치해야 함을 상징합니다. "왕이여 만세 수를 누리소서"라는 백성들의 환호는 정당한 다윗 왕조의 회복에 대한 기쁨의 표현이었습니다. 이 모든 과정에서 여호야다는 성전의 거룩함을 지키려 애썼고, 아달랴조차도 성전이 아닌 왕궁 말문에서 처형되도록 했습니다.\n\n개혁은 정치적 차원을 넘어 신앙의 회복으로 이어집니다. 여호야다는 자기와 모든 백성과 왕 사이에 언약을 세워 "여호와의 백성이 되리라"고 선언합니다. 백성들은 바알 신당을 부수고 그 제사장을 죽였으며, 여호야다는 다윗이 정한 규례대로 성전 예배를 회복시킵니다. 레위 제사장들이 모세의 율법에 따라 번제를 드리며 즐거이 찬송하는 모습은 참된 예배의 회복을 보여줍니다.\n\n이 모든 개혁의 결과로 "그 땅의 모든 백성이 즐거워하고 성중이 평온하더라"는 기록은 하나님의 질서가 회복될 때 오는 참된 평화를 증거합니다. 한 사람의 신실한 제사장을 통해 무너진 신앙이 회복되고 나라가 새로워지는 은혜의 역사가 일어난 것입니다.', E'오늘의 핵심\n하나님께서는 신실한 제사장 여호야다를 통해 우상숭배로 타락한 남유다에 다윗 왕조를 회복시키시고, 성전 예배와 언약 백성의 정체성을 되찾게 하셨습니다.\n\n묵상 질문\n1. 여호야다처럼 때를 기다리며 신앙의 개혁을 준비하는 인내와 지혜가 내게 있나요?\n2. 우리 시대에 무너져가는 신앙의 전통과 가치를 회복하기 위해 나는 무엇을 할 수 있을까요?\n3. "여호와의 백성이 되리라"는 언약이 내 삶에서는 어떻게 구체화되고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-12', E'요아스와 여호야다의 개혁 (역대하 24장)', E'역대하 24장', E'남유다 역사에서 가장 극적인 개혁이 일어났습니다. 어린 나이에 왕위에 오른 요아스는 제사장 여호야다의 보호와 가르침 아래서 하나님 보시기에 정직한 왕으로 성장합니다. 아달랴의 폭정으로 무너진 성전을 보수하고자 하는 왕의 열정은 백성들의 마음을 움직였고, 자발적인 헌금으로 성전은 "이전 모양대로 견고하게" 회복되었습니다. 여호야다가 살아있는 동안 남유다는 하나님께 드리는 제사가 끊이지 않는 신앙의 황금기를 누렸습니다.\n\n그러나 한 사람의 영향력이 얼마나 중요한지를 보여주는 반전이 일어납니다. 130세를 일기로 여호야다가 세상을 떠나자, 요아스는 완전히 다른 사람이 되어버립니다. 유다 방백들의 아첨에 넘어간 왕은 조상들의 하나님 여호와의 전을 버리고 우상숭배에 빠집니다. 하나님께서는 선지자들을 보내 경고하셨지만, 요아스는 듣지 않았을 뿐만 아니라 자신을 책망하는 여호야다의 아들 스가랴를 성전 뜰에서 돌로 쳐죽이는 패역을 저지릅니다. 은인의 아들을 죽인 배은망덕한 왕의 최후는 비참했습니다. 작은 아람 군대에게 패하고, 신하들의 손에 암살당하며, 왕들의 묘실에도 들지 못하는 수치를 당합니다.\n\n요아스의 이야기는 신앙이 단지 환경의 산물이 아님을 가르쳐줍니다. 여호야다의 선한 영향력 아래서도, 그의 신앙은 뿌리를 내리지 못했습니다. 외적인 개혁은 있었지만 내면의 변화는 없었던 것입니다. 진정한 신앙은 누군가의 감독 아래서만 유지되는 것이 아니라, 하나님과의 인격적인 관계 속에서 자라나는 것임을 깨닫게 됩니다.', E'오늘의 핵심\n요아스의 극적인 변화는 외적 영향력에만 의존하는 신앙의 위험성을 보여주며, 하나님과의 진정한 관계가 얼마나 중요한지 일깨워줍니다.\n\n묵상 질문\n1. 나의 신앙은 누군가의 영향력에 의존하고 있지는 않은가요?\n2. 하나님께서 내게 주신 은혜를 기억하고 감사하며 살고 있나요?\n3. 신앙의 뿌리를 깊이 내리기 위해 오늘 무엇을 결단해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-13', E'요아스와 여호야다의 개혁 (역대하 25장)', E'역대하 25장', E'아마샤는 부왕 요아스를 죽인 신하들을 처형하면서도 그들의 자녀는 살려둡니다. 이는 모세 율법의 가르침을 따른 것으로, 각 사람이 자기 죄로 인해 죽어야 한다는 원칙을 지킨 것입니다. 왕위 초기에는 율법을 존중하는 모습을 보였던 아마샤였으나, 역대기 기자는 그가 "여호와께서 보시기에 정직하게 행하기는 하였으나 온전한 마음으로 행하지 아니하였더라"고 평가합니다. 이 평가는 곧 그의 통치 전체를 관통하는 예언이 되었습니다.\n\n아마샤는 에돔과의 전쟁을 앞두고 은 백 달란트로 북이스라엘의 용병 십만 명을 고용합니다. 그러나 하나님의 사람은 여호와께서 북이스라엘과 함께하지 않으신다며 이들을 돌려보낼 것을 권고합니다. 아마샤는 아까운 마음에도 불구하고 이 권고를 받아들여 북이스라엘 군대를 돌려보냅니다. 그 결과 하나님의 도우심으로 에돔과의 전쟁에서 승리를 거둡니다.\n\n그런데 승리 후 아마샤의 행동은 충격적입니다. 그는 패배한 에돔의 신상들을 가져와 자신의 신으로 섬기며 분향합니다. 자기 백성도 구원하지 못한 무력한 신들을 섬기는 모순된 행동에 대해 선지자가 책망하자, 아마샤는 오히려 선지자를 위협합니다. 하나님을 온전히 신뢰하지 못하는 그의 반쪽짜리 신앙이 여기서 드러납니다.\n\n교만해진 아마샤는 북이스라엘에 도전장을 보내지만, 오히려 크게 패하고 포로가 되어 예루살렘 성벽 일부가 헐리고 성전과 왕궁의 보물을 약탈당합니다. 에돔의 신들에게 절한 결과로 하나님께서 그를 대적의 손에 넘기신 것입니다. 결국 아마샤는 부왕처럼 반역으로 죽임을 당합니다. 온전하지 못한 신앙, 승리 후의 교만, 우상숭배가 그를 파멸로 이끈 것입니다.', E'오늘의 핵심\n아마샤의 불완전한 순종과 승리 후의 교만, 그리고 우상숭배는 결국 그를 패배와 죽음으로 이끌었습니다. 하나님은 온전한 마음으로 섬기는 신앙을 원하십니다.\n\n묵상 질문\n1. 나는 하나님을 온전한 마음으로 섬기고 있나요, 아니면 상황에 따라 타협하는 신앙을 가지고 있나요?\n2. 성공과 승리의 순간에 오히려 하나님을 잊고 교만해진 적은 없었나요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 ''에돔의 신들''은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-15', E'웃시야 요담 아하스 시대 (역대하 26장)', E'역대하 26장', E'유다 백성은 열여섯 살의 웃시야를 왕으로 세웁니다. 어린 나이에 왕위에 오른 웃시야는 하나님 보시기에 정직하게 행하며, 하나님의 묵시를 밝히 아는 스가랴의 영적 지도를 받았습니다. 그가 여호와를 찾을 동안 하나님께서는 그를 형통하게 하셨고, 블레셋과 아라비아 사람들과의 전쟁에서 승리를 주셨습니다. 암몬 사람들이 조공을 바칠 정도로 웃시야의 명성은 애굽 변방까지 퍼져나갔습니다.\n\n웃시야는 국방을 강화하고 농업을 진흥시키는 탁월한 통치력을 보였습니다. 예루살렘 성벽을 견고히 하고 광야에 망대를 세웠으며, 물 웅덩이를 파서 목축업을 발전시켰습니다. 삼십만이 넘는 강한 군대를 조직하고 당시 최신 무기들을 개발하여 배치했습니다. 성경은 그가 "기이한 도우심을 얻어 강성하여졌다"고 기록합니다. 하나님의 특별한 은혜가 그와 함께했던 것입니다.\n\n그러나 강성함이 오히려 웃시야를 넘어뜨리는 원인이 되었습니다. 마음이 교만해진 그는 제사장만이 할 수 있는 분향을 자신이 직접 하려고 성전에 들어갔습니다. 아사랴를 비롯한 팔십 명의 제사장들이 용감하게 왕의 잘못을 지적했지만, 웃시야는 분노했습니다. 바로 그 순간 그의 이마에 나병이 나타났습니다. 하나님께서 직접 개입하신 것입니다. \n\n나병에 걸린 웃시야는 죽는 날까지 별궁에 격리되어 살았습니다. 오십이 년의 긴 통치 기간 중 대부분을 하나님과 동행하며 성공적으로 보냈지만, 교만으로 인한 한 번의 실수가 그의 말년을 비극으로 만들었습니다. 하나님께서 주신 형통함 속에서도 겸손을 잃지 않는 것이 얼마나 중요한지를 웃시야의 생애가 보여줍니다.', E'오늘의 핵심\n하나님을 찾는 동안 형통했던 웃시야는 강성해진 후 교만하여 하나님께서 정하신 경계를 넘었고, 그 결과 나병으로 심판받아 격리된 채 생을 마감했습니다.\n\n묵상 질문\n1. 웃시야가 하나님을 찾을 때와 교만해졌을 때의 차이는 우리에게 무엇을 가르쳐 주나요?\n2. 성공과 형통함 속에서도 하나님 앞에 겸손을 유지하려면 어떻게 해야 할까요?\n3. 내 삶에서 하나님이 정하신 경계를 넘으려는 교만한 마음은 없는지 돌아볼 때입니다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-16', E'웃시야 요담 아하스 시대 (역대하 27장)', E'역대하 27장', E'남유다의 역사는 선한 왕과 악한 왕이 번갈아 나타나는 영적 롤러코스터와 같았습니다. 웃시야가 한센병으로 격리된 후 그의 아들 요담이 25세의 나이로 왕위에 올랐습니다. 역대기 기자는 요담이 아버지 웃시야의 모든 행위대로 여호와 보시기에 정직하게 행하였다고 평가합니다. 그러나 이 평가에는 중요한 단서가 붙어 있습니다. "여호와의 성전에는 들어가지 아니하였고"라는 구절이 그것입니다. 아버지가 성전에서 분향하다가 한센병에 걸린 일이 요담에게는 깊은 트라우마로 남았던 것 같습니다. 성전을 경외하는 마음은 좋았지만, 그것이 성전을 멀리하는 것으로 나타난 것은 안타까운 일이었습니다.\n\n더욱 심각한 문제는 "백성은 여전히 부패하였더라"는 기록입니다. 요담 개인은 하나님 앞에서 바른 길을 걸었지만, 백성들의 영적 상태는 계속 악화되고 있었습니다. 이는 지도자 한 사람의 개인적 신앙만으로는 한 나라 전체의 영적 흐름을 바꾸기 어렵다는 것을 보여줍니다. 요담은 16년간 통치하면서 많은 건축 사업을 진행했습니다. 성전의 윗문을 건축하고, 오벨 성벽을 증축하며, 산중에 성읍들을 세우고, 견고한 진영들과 망대를 건축했습니다. 암몬과의 전쟁에서도 승리하여 막대한 조공을 받았습니다.\n\n역대기 기자는 요담이 강성해진 이유를 명확하게 제시합니다. "요담이 그의 하나님 여호와 앞에서 바른 길을 걸었으므로 점점 강하여졌더라"는 것입니다. 이는 하나님과의 관계가 한 나라의 흥망성쇠를 결정한다는 역대기의 일관된 신학을 보여줍니다. 그러나 요담의 선한 통치에도 불구하고 백성들의 부패는 결국 다음 왕인 아하스 시대에 영적 재앙으로 나타나게 됩니다. 개인의 경건과 공동체의 신앙은 함께 가야 한다는 교훈을 남겨줍니다.', E'오늘의 핵심\n요담은 개인적으로 하나님 앞에서 바른 길을 걸어 강성해졌지만, 백성들의 영적 부패를 막지는 못했습니다. 지도자의 개인적 경건만으로는 공동체 전체의 영적 회복을 이루기 어렵다는 것을 보여줍니다.\n\n묵상 질문\n1. 아버지의 실패가 트라우마가 되어 성전을 멀리한 요담처럼, 나도 과거의 상처로 인해 하나님께 온전히 나아가지 못하는 부분이 있을까요?\n2. 요담이 하나님 앞에서 바른 길을 걸어 강성해진 것처럼, 내 삶의 형통함의 근원이 하나님과의 관계에 있음을 인정하고 있나요?\n3. 지도자는 바르게 살았지만 백성은 부패했던 것처럼, 내 주변 공동체의 영적 건강을 위해 내가 할 수 있는 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-17', E'웃시야 요담 아하스 시대 (역대하 28장)', E'역대하 28장', E'남유다의 역사에서 가장 어두운 장면 중 하나가 펼쳐집니다. 아하스가 스무 살에 왕위에 오르면서 유다는 영적으로 급속히 타락하기 시작합니다. 그의 조상 다윗과는 정반대의 길을 걸으며, 북이스라엘의 악한 왕들을 본받아 바알 우상을 만들어 섬겼습니다. 더욱 충격적인 것은 힌놈의 아들 골짜기에서 자기 자녀들을 불에 태워 제사하는 가증한 일까지 행했다는 사실입니다. 이는 하나님께서 가나안 민족을 심판하신 바로 그 죄악이었습니다.\n\n하나님의 심판은 즉각적으로 임했습니다. 아람과 북이스라엘의 침략으로 하루에만 십이만 명의 용사가 죽고, 이십만 명이 포로로 잡혀갔습니다. 그러나 이 비극 속에서도 하나님의 긍휼이 나타납니다. 북이스라엘의 선지자 오뎃과 지도자들이 나서서 유다 포로들을 돌려보내게 했던 것입니다. "너희의 형제들 중에서 사로잡아 온 포로를 놓아 돌아가게 하라"(대하 28:11)는 오뎃의 외침은 남북이 한 형제임을 일깨워주는 하나님의 음성이었습니다.\n\n그럼에도 아하스는 회개하지 않았습니다. 오히려 앗수르에게 도움을 요청하며 성전과 왕궁의 재물을 바쳤지만, 앗수르는 도움은커녕 유다를 공격했습니다. 곤경에 처할수록 아하스는 더욱 하나님을 거역했습니다. 다메섹의 신들에게 제사하고, 성전 문을 닫으며, 예루살렘 곳곳에 우상의 제단을 세웠습니다. 하나님을 의지하지 않고 인간적인 방법과 우상을 의지한 결과는 철저한 실패였습니다.\n\n아하스의 이야기는 신앙의 유산이 한 세대만에 무너질 수 있음을 보여줍니다. 경건한 조상들의 믿음도 개인의 선택 앞에서는 무력합니다. 각 사람은 하나님 앞에서 자신의 신앙을 선택하고 책임져야 합니다. 위기의 때일수록 하나님께 더 가까이 나아가야 하는데, 아하스는 정반대로 행했습니다. 그의 실패는 오늘 우리에게 경고의 메시지가 됩니다.', E'오늘의 핵심\n아하스는 위기 앞에서 하나님을 버리고 우상과 세상 권력을 의지했으나, 그 결과는 더 큰 재앙과 실패였습니다. 곤경 속에서도 하나님께 돌아가지 않는 완악함이 그를 파멸로 이끌었습니다.\n\n묵상 질문\n1. 어려움을 만날 때 나는 먼저 하나님께 나아가나요, 아니면 인간적인 해결책부터 찾나요?\n2. 신앙의 유산을 물려받았다면, 그것을 나의 개인적 신앙으로 만들고 있나요?\n3. 실패와 곤경이 오히려 하나님과 멀어지게 만드는 것은 아닌지 점검해볼 필요가 있지 않을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-18', E'히스기야의 개혁정치 (역대하 29장)', E'역대하 29장', E'아하스의 뒤를 이어 왕위에 오른 히스기야가 첫 번째로 착수한 일은 하나님의 전을 성결하게 하는 일이었습니다. 아버지 아하스가 16년간 우상숭배로 나라를 어둠 속에 빠뜨렸던 것과는 정반대의 길이었습니다. 25세의 젊은 왕은 즉위 첫 달에 곧바로 닫혔던 성전 문을 열고 수리하기 시작합니다. 제사장들과 레위인들을 불러 모은 히스기야는 남유다가 처한 비참한 현실을 직시합니다. 조상들이 하나님을 버리고 성전을 등졌기에 백성들이 칼에 쓰러지고 자녀와 아내들이 포로로 잡혀갔다는 것입니다.\n\n히스기야는 레위인들에게 "내 아들들아 이제는 게으르지 말라"(대하 29:11)고 격려하며 성전 정화 작업을 명령합니다. 이 말에 레위인들이 즉각 응답하여 16일간의 대대적인 정화 작업이 시작됩니다. 제사장들은 성전 안으로 들어가 모든 더러운 것을 끌어내고, 레위인들은 그것을 받아 기드론 시내로 가져갔습니다. 아하스가 버렸던 성전 기구들도 다시 정돈하고 성결하게 하여 제자리에 놓았습니다.\n\n성전 정화가 끝나자 히스기야는 곧바로 속죄제와 번제를 드립니다. 수송아지와 숫양, 어린 양과 숫염소를 각각 일곱 마리씩 준비하여 나라와 성소와 유다를 위한 속죄제물로 삼았습니다. 다윗 시대의 찬양대를 복원하여 제금과 비파와 수금으로 여호와를 찬송하게 했고, 제사장들은 나팔을 불었습니다. 온 회중이 함께 경배하며 즐거움으로 찬송했고, 자원하여 제물과 감사제물을 가져왔습니다. 놀랍게도 레위인들의 헌신이 제사장들보다 더 성심이 있었다고 기록되어 있습니다. 이렇게 여호와의 전에서 섬기는 일이 순서대로 갖추어지자, 히스기야와 백성들은 하나님께서 이 일을 예비하셨음을 깨닫고 기뻐했습니다.', E'오늘의 핵심\n히스기야는 즉위하자마자 닫혔던 성전 문을 열고 대대적인 정화 작업을 통해 예배를 회복함으로써, 우상숭배로 어두웠던 남유다에 영적 개혁의 서막을 열었습니다.\n\n묵상 질문\n1. 히스기야가 왕이 되어 가장 먼저 성전을 정화한 이유는 무엇일까요?\n2. 내 삶에서 하나님과의 관계를 가로막는 ''더러운 것''들은 무엇인가요?\n3. 레위인들처럼 성심을 다해 하나님을 섬기려면 어떤 결단이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-19', E'히스기야의 개혁정치 (역대하 30장)', E'역대하 30장', E'히스기야가 성전을 정결하게 한 후 착수한 일은 오랫동안 제대로 지켜지지 못했던 유월절을 회복하는 것이었습니다. 왕은 남유다뿐 아니라 북이스라엘 지역인 에브라임과 므낫세에까지 편지를 보내어 예루살렘으로 와서 유월절을 지키자고 초청합니다. 이는 이미 앗수르에 의해 멸망한 북이스라엘의 남은 백성들까지 포용하려는 히스기야의 넓은 마음을 보여줍니다.\n\n보발꾼들이 전한 메시지는 단순한 절기 준수의 권면이 아니었습니다. "너희는 아브라함과 이삭과 이스라엘의 하나님 여호와께로 돌아오라"(대하 30:6)는 회개의 촉구였으며, 조상들의 실패를 반면교사로 삼아 하나님께 돌아오라는 간절한 호소였습니다. 비록 많은 이들이 이 초청을 조롱하고 비웃었지만, 아셀과 므낫세와 스불론 중 일부는 겸손한 마음으로 예루살렘에 올라왔습니다.\n\n유월절 준비가 완벽하지는 않았습니다. 많은 백성이 정결 예식을 제대로 거치지 못한 채 유월절 양을 먹었고, 이는 율법을 어기는 일이었습니다. 그러나 히스기야는 이들을 위해 중보기도를 드렸습니다. 그는 형식적 정결보다 하나님을 향한 진실한 마음이 더 중요함을 알았던 것입니다. 여호와께서는 왕의 기도를 들으시고 백성을 고치셨습니다.\n\n이렇게 시작된 유월절은 큰 기쁨의 축제가 되었습니다. 원래 7일간 지키는 절기였지만 백성들은 너무나 즐거워서 7일을 더 지키기로 결의했습니다. 솔로몬 시대 이후로 이런 기쁨이 예루살렘에 없었다고 기록될 정도로, 하나님과의 관계 회복은 넘치는 기쁨을 가져다주었습니다. 제사장과 레위인들의 축복의 소리가 하늘에 상달되었다는 표현은 하나님께서 이 모든 예배를 기쁘게 받으셨음을 보여줍니다.', E'오늘의 핵심\n히스기야는 남북을 아우르는 유월절 회복을 통해 분열된 백성을 하나로 모으고, 형식보다 마음을 중시하는 참된 예배의 기쁨을 경험하게 했습니다.\n\n묵상 질문\n1. 하나님께로 돌아오라는 초청을 거절하거나 조롱하는 마음이 내 안에는 없나요?\n2. 종교적 형식과 규례를 지키는 것과 진실한 마음으로 하나님을 찾는 것 중 무엇이 더 중요할까요?\n3. 하나님과의 관계 회복이 가져다주는 기쁨을 최근에 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-20', E'히스기야의 개혁정치 (역대하 31장)', E'역대하 31장', E'유월절 축제가 끝나자 백성들의 마음에 놀라운 변화가 일어났습니다. 거기 모였던 이스라엘 무리가 자발적으로 나가서 유다와 베냜민, 에브라임과 므낫세 온 땅의 주상들과 아세라 목상을 부수고 산당과 제단들을 완전히 제거했습니다. 히스기야가 명령하기 전에 백성들이 스스로 우상을 척결한 것은 하나님을 향한 그들의 마음이 진심으로 회복되었음을 보여줍니다.\n\n히스기야는 이제 하나님께 드리는 예배가 지속적으로 이루어질 수 있도록 제도적 기반을 마련합니다. 제사장과 레위인들의 반열을 정하고 각자의 직무를 명확히 하여, 번제와 화목제를 드리며 성전에서 감사와 찬송이 끊이지 않게 했습니다. 또한 왕의 재산에서 정기적인 번제 비용을 충당하고, 백성들에게는 제사장과 레위인들의 생활을 책임지도록 했습니다. 이는 그들이 생계 걱정 없이 여호와의 율법을 힘써 지킬 수 있게 하려는 배려였습니다.\n\n왕의 명령이 내려지자 백성들의 반응은 즉각적이고도 넘치는 것이었습니다. 곡식과 포도주, 기름과 꿀 등 밭에서 나는 모든 소산의 첫 열매를 풍성히 드렸고, 십일조도 많이 가져왔습니다. 셋째 달부터 일곱째 달까지 계속해서 예물이 쌓여 여러 더미를 이루었습니다. 대제사장 아사랴는 "백성이 예물을 여호와의 전에 드리기 시작함으로부터 우리가 만족하게 먹었으나 남은 것이 많으니 이는 여호와께서 그의 백성에게 복을 주셨음이라"(대하 31:10)고 증언합니다.\n\n히스기야는 넘치는 예물을 체계적으로 관리하기 위해 성전에 창고를 준비하고, 신실한 레위인들을 책임자로 세워 공정하게 분배하도록 했습니다. 제사장과 레위인뿐 아니라 그들의 가족들까지 빠짐없이 돌보았고, 성읍 밖에 사는 이들도 놓치지 않았습니다. 이러한 히스기야의 개혁은 선과 정의와 진실함으로 이루어졌고, 그가 한 마음으로 하나님을 찾고 섬겼기에 모든 일이 형통했습니다. 진정한 영적 부흥은 예배의 회복과 함께 삶의 모든 영역에서 하나님의 뜻을 구하고 실천할 때 열매를 맺게 됩니다.', E'오늘의 핵심\n히스기야의 개혁은 백성들의 자발적인 우상 제거와 넘치는 헌신으로 이어졌고, 체계적인 성전 운영을 통해 지속가능한 예배 공동체를 세워갔습니다.\n\n묵상 질문\n1. 하나님께서 내 삶에 부어주신 넘치는 은혜를 어떻게 감사로 표현하고 있나요?\n2. 나는 하나님의 일을 위해 물질과 시간을 기쁘게 드리고 있나요?\n3. 히스기야처럼 한 마음으로 하나님을 찾으며 모든 일을 행하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-22', E'파수군으로의 부르심 (에스겔 1장)', E'에스겔 1장', E'여호야긴 왕이 바벨론에 포로로 잡혀간 지 5년째 되던 해, 그발 강가에서 제사장 에스겔에게 특별한 일이 일어납니다. 하나님께서 그에게 영광스러운 환상을 보여주신 것입니다. 북방에서 몰아치는 폭풍과 큰 구름, 그 속에서 번쩍이는 불빛은 하나님의 임재가 얼마나 위엄 있고 두려운 것인지를 보여줍니다. \n\n환상 가운데 나타난 네 생물의 모습은 하나님의 창조 세계 전체를 대표하는 듯합니다. 사람과 사자, 소와 독수리의 얼굴을 가진 이 신비로운 존재들은 하나님의 영이 이끄시는 대로 일사불란하게 움직입니다. 그들은 결코 뒤돌아보지 않고 오직 앞으로만 나아가는데, 이는 하나님의 뜻이 얼마나 확고하고 변함없는지를 상징적으로 보여줍니다.\n\n특히 주목할 것은 바퀴 안에 바퀴가 있는 신비한 구조입니다. 생물의 영이 바퀴 가운데 있어서 생물이 가는 곳마다 바퀴도 함께 움직입니다. 이는 하나님의 통치가 우주 만물에 미치지 않는 곳이 없음을 나타냅니다. 수정 같은 궁창 위에 계신 하나님의 모습은 "비 오는 날 구름에 있는 무지개"(겔 1:28)처럼 찬란한 영광으로 가득합니다.\n\n포로 생활의 절망 가운데 있던 에스겔과 유다 백성에게 이 환상은 특별한 의미가 있었을 것입니다. 비록 그들이 이방 땅에 포로로 잡혀 있지만, 하나님의 영광과 통치는 예루살렘 성전에만 국한되지 않습니다. 하나님께서는 바벨론 땅에서도 여전히 당신의 백성과 함께하시며, 그들을 향한 계획을 포기하지 않으셨음을 보여주십니다. 에스겔이 그 영광 앞에 엎드릴 수밖에 없었듯이, 우리도 하나님의 위엄과 영광 앞에 겸손히 무릎 꿇는 자세가 필요합니다.', E'오늘의 핵심\n포로 생활의 절망 속에서도 하나님께서는 에스겔에게 당신의 영광스러운 환상을 보여주시며, 여전히 역사를 주관하시는 전능하신 하나님이심을 계시하십니다.\n\n묵상 질문\n1. 절망적인 상황에서도 하나님의 영광과 임재를 경험한 적이 있으신가요?\n2. 하나님의 뜻이 ''돌이키지 않고 앞으로만 가는'' 것처럼 확고할 때, 나는 어떻게 반응하나요?\n3. 에스겔처럼 하나님의 영광 앞에 엎드려본 경험이 있다면 나누어보실 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-23', E'파수군으로의 부르심 (에스겔 2장)', E'에스겔 2장', E'에스겔이 하나님의 영광을 목격하고 엎드린 후, 하나님께서는 그를 일으켜 세우시며 선지자로서의 소명을 주십니다. "인자야 네 발로 일어서라 내가 네게 말하리라"(겔 2:1)는 음성과 함께 성령이 에스겔에게 임하여 그를 일으켜 세우십니다. 이는 단순히 육체적으로 일어서는 것이 아니라, 하나님의 사명을 감당할 수 있도록 영적으로 세워주시는 은혜의 순간입니다.\n\n하나님께서는 에스겔을 보내실 곳이 어디인지 분명히 알려주십니다. 패역한 백성, 하나님을 배반하는 이스라엘 자손에게 보내신다고 말씀하십니다. 그들은 얼굴이 뻔뻔하고 마음이 굳은 자들이며, 조상 대대로 하나님께 범죄하여 온 족속입니다. 그럼에도 불구하고 하나님께서는 여전히 그들에게 말씀을 전하기 원하십니다. 비록 그들이 듣지 않을지라도, 그들 가운데 선지자가 있음을 알게 하려는 것입니다.\n\n에스겔의 사역이 얼마나 어려울지를 미리 아시는 하나님께서는 "가시와 찔레와 함께 있으며 전갈 가운데 거주할지라도" 두려워하지 말라고 격려하십니다. 이는 에스겔이 직면할 적대와 위험을 생생하게 표현한 것입니다. 그러나 하나님께서는 패역한 족속의 말과 그들의 얼굴을 무서워하지 말라고 거듭 당부하십니다.\n\n하나님께서는 에스겔에게 두루마리를 주시며 그것을 먹으라고 명하십니다. 그 두루마리에는 애가와 애곡과 재앙의 말이 기록되어 있었습니다. 이는 에스겔이 전해야 할 메시지의 무거움을 보여줍니다. 선지자는 하나님의 말씀을 단순히 전달하는 것이 아니라, 그 말씀을 온전히 소화하고 자신의 것으로 만들어야 합니다. 말씀을 먹는다는 것은 그 말씀과 하나가 되어 살아내는 것을 의미합니다.', E'오늘의 핵심\n하나님께서는 패역한 백성에게 보내실 에스겔을 성령으로 일으켜 세우시고, 두려움 없이 말씀을 전하도록 준비시키십니다. 선지자의 사명은 백성의 반응과 상관없이 하나님의 말씀을 신실하게 전하는 것입니다.\n\n묵상 질문\n1. 하나님께서 나를 일으켜 세우실 때, 나는 어떻게 응답하고 있나요?\n2. 복음을 전하기 어려운 환경에서도 담대할 수 있는 힘은 어디서 오나요?\n3. 하나님의 말씀을 ''먹는다''는 것이 내 삶에서는 어떤 의미일까요?');
